import type { ByteCard } from './bytes';

/*
 * The starter pack — correct, sourced, hand-written. Loaded on demand from the
 * Bytes deck ("Load starter pack"). Fixed ids so re-loading dedups instead of
 * duplicating. Cards are stamped with `updatedAt` at load time.
 */
export const STARTER_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_ml_attention', pack: 'foundations', topic: 'ml', level: 1, title: 'Attention is a weighted average', blurb: "Each token's new vector is a softmax-weighted sum of every other token's value. The weights ARE the attention — that's how a transformer reads a sentence whole, with no recurrence.", source: 'Vaswani et al., 2017', detail: "QUERY, KEY, VALUE\nEach token makes three vectors. A query asks who matters to me, keys answer, and the match scores decide how much of each value to take.\nTHE WEIGHTED SUM\nScore every token against every other (dot product), softmax the scores into weights that sum to 1, then the new vector is that weighted sum of values. The weights ARE the attention.\nWHY IT WINS\nNo recurrence — every token sees every other in ONE step, so it parallelises on a GPU and captures long-range links a sequence model would forget.\nMULTI-HEAD\nDo it several times in parallel, each head learning a different relation (syntax, coreference), then concatenate.\nREMEMBER\nAttention = softmax(scores) applied to values — reading the whole sentence at once." },
  { id: 'b_ml_gradient', pack: 'foundations', topic: 'ml', level: 1, title: 'Gradient descent walks downhill', blurb: 'The gradient points toward steepest increase of the loss. Step the opposite way, a little at a time, and you slide toward a minimum. The step size is the learning rate.', detail: "THE PICTURE\nImagine the loss as a hilly landscape and your weights as your position on it. The gradient points to the steepest UPHILL — so step the opposite way to go down.\nTHE STEP SIZE\nThe learning rate is how big each step is. Too big and you overshoot or diverge; too small and it crawls. Most training pain is really learning-rate pain.\nMINI-BATCHES\nComputing the gradient on all the data is slow, so we use small batches — noisier steps, but far more of them. That is stochastic gradient descent.\nREMEMBER\nGradient points uphill; step downhill by the learning rate." },
  { id: 'b_ml_lr', pack: 'foundations', topic: 'ml', level: 1, title: 'Learning rate: the Goldilocks knob', blurb: 'Too high and training diverges; too low and it crawls or gets stuck. Most tuning pain is really learning-rate pain.' },
  { id: 'b_ml_overfit', pack: 'foundations', topic: 'ml', level: 2, title: 'Overfitting is memorising', blurb: 'Low training error but high test error means the model memorised noise. Cures: more data, regularisation, dropout, or a simpler model.', detail: "THE TELL\nTraining error keeps falling while validation error starts CLIMBING. The model is fitting noise it will never see again, not the signal.\nWHY IT HAPPENS\nToo much capacity for too little data: enough parameters to memorise the training set instead of generalising from it.\nTHE CURES\nMore data. A simpler model. Regularisation, dropout, early stopping — each stops the model leaning on quirks of the training rows.\nTHE MIRROR IMAGE\nUnderfitting is the opposite: too simple, high error on BOTH sets. The craft is landing between the two.\nREMEMBER\nMemorised the noise? That is overfitting — a held-out test set catches it." },
  { id: 'b_ml_biasvar', pack: 'foundations', topic: 'ml', level: 2, title: 'Bias vs variance', blurb: 'High bias underfits (too simple). High variance overfits (too flexible, swings with the data). You trade one for the other.', detail: "THE TWO ERRORS\nBias is being wrong on average (too simple — underfits). Variance is being unstable (too flexible — swings with the exact training data, overfits).\nTHE TRADEOFF\nMake a model more complex and bias falls but variance rises. Total error is a U — the sweet spot is in the middle, not the extremes.\nHOW TO TELL\nHigh training AND test error means bias (underfit). Low training but high test error means variance (overfit).\nTHE FIXES\nUnderfit? More features, a richer model. Overfit? More data, regularisation, or a simpler model.\nREMEMBER\nUnderfit = bias. Overfit = variance." },
  { id: 'b_ml_softmax', pack: 'foundations', topic: 'ml', level: 2, title: 'Softmax turns scores into probabilities', blurb: 'Exponentiate each logit, then divide by the sum. Output is positive and sums to 1 — a probability distribution over classes.', code: 'p_i = exp(z_i) / sum(exp(z_j))', lang: 'text' },
  { id: 'b_ml_backprop', pack: 'foundations', topic: 'ml', level: 3, title: 'Backprop is just the chain rule', blurb: "Multiply local derivatives backward through the network to get each weight's effect on the loss. Nothing mystical — calculus, layer by layer.", detail: "THE GOAL\nTraining needs to know how much each weight moved the loss. Backprop computes every one of those partial derivatives in a single backward pass.\nTHE CHAIN RULE\nThe loss is a composition of layers, so the derivative of the whole is the product of the local derivatives — multiplied together, output back toward input.\nFORWARD THEN BACKWARD\nThe forward pass caches each layer's inputs. The backward pass reuses them to turn one downstream gradient into the gradient for the layer below — nothing recomputed.\nNOT MAGIC\nIt is bookkeeping: the same calculus you would do by hand, organised so an n-layer net costs about one extra pass, not n of them.\nREMEMBER\nBackprop = the chain rule, applied layer by layer, backward." },
  { id: 'b_ai_tokens', pack: 'foundations', topic: 'ai', level: 1, title: 'LLMs think in tokens, not words', blurb: "Text is split into tokens (~4 chars). The model predicts the next token, over and over. The 'context window' is how many it can see at once." },
  { id: 'b_ai_temp', pack: 'foundations', topic: 'ai', level: 2, title: 'Temperature = how bold the guess', blurb: 'It reshapes the next-token odds. Near 0 = always the likeliest token (focused). Higher = flatter odds (creative, riskier).' },
  { id: 'b_ai_halluc', pack: 'foundations', topic: 'ai', level: 2, title: "Why models 'hallucinate'", blurb: 'An LLM predicts plausible text, not verified truth. Fluent-and-wrong is a normal output. Grounding it in real sources (RAG) is how you fight it.', detail: "THE ROOT CAUSE\nAn LLM is trained to predict PLAUSIBLE next tokens, not to check truth. Fluent-and-wrong is a perfectly normal output — there is no built-in fact detector.\nCONFIDENT NONSENSE\nIt fills a gap the way its training data usually reads: a citation SHAPED right, a function that LOOKS real. The style convinces precisely because it is learned from real text.\nTHE FIXES\nGround it in retrieved sources (RAG) so it answers FROM documents. Ask for citations. Lower the temperature. Let it decline when unsure. Verify anything that matters.\nNOT A BUG TO PATCH\nIt is the flip side of fluency and creativity. You manage it; you do not fully remove it.\nREMEMBER\nModels predict plausible text, not verified truth — ground it and check." },
  { id: 'b_sql_leftjoin', pack: 'foundations', topic: 'sql', level: 1, title: 'LEFT JOIN keeps every left row', blurb: "Unmatched right-side columns come back NULL — so a LEFT JOIN never drops a row from the left table. Filter for the NULLs to find 'has none'.", code: 'SELECT u.name\nFROM users u\nLEFT JOIN orders o ON o.user_id = u.id\nWHERE o.id IS NULL;', lang: 'sql' },
  { id: 'b_sql_wherehaving', pack: 'foundations', topic: 'sql', level: 2, title: 'WHERE before, HAVING after', blurb: "WHERE filters rows before grouping. HAVING filters groups after aggregation. You can't put an aggregate in WHERE.", code: 'SELECT dept, COUNT(*)\nFROM emp\nGROUP BY dept\nHAVING COUNT(*) > 5;', lang: 'sql' },
  { id: 'b_sql_null', pack: 'foundations', topic: 'sql', level: 1, title: 'NULL equals nothing', blurb: "NULL means 'unknown', so NULL = NULL is not true — it's NULL. Always test with IS NULL / IS NOT NULL, never = NULL." },
  { id: 'b_sql_index', pack: 'foundations', topic: 'sql', level: 2, title: 'Indexes trade writes for reads', blurb: 'An index is a sorted lookup: it makes matching queries fast, but every insert/update must maintain it. Index what you filter and join on — not everything.' },
  { id: 'b_py_comprehension', pack: 'foundations', topic: 'python', level: 1, title: 'Comprehensions build; loops mutate', blurb: 'One expression returns a new list — clearer and faster than appending in a loop.', code: 'squares = [n*n for n in xs if n % 2 == 0]', lang: 'python' },
  { id: 'b_py_defaultarg', pack: 'foundations', topic: 'python', level: 3, title: 'The mutable-default trap', blurb: "A default list is created once, at definition — so it's SHARED across calls and quietly accumulates. Use None and make a fresh one inside.", code: 'def add(x, acc=None):\n    acc = acc or []\n    acc.append(x)\n    return acc', lang: 'python', detail: "THE BUG\n```python\ndef add(x, acc=[]):\n    acc.append(x)\n    return acc\n\nadd(1)  # [1]\nadd(2)  # [1, 2]  <- surprise!\n```\nWHY\nDefault arguments are evaluated ONCE, when the function is defined — not on each call. So that one list is shared across every call, quietly accumulating.\nTHE FIX\nDefault to None, and build a fresh object inside:\n```python\ndef add(x, acc=None):\n    acc = acc or []\n    acc.append(x)\n    return acc\n```\nIT IS EVERYWHERE\nSame trap with {}, sets, and dataclass fields. Any mutable default is suspect — and a call like datetime.now() as a default fires once at import, not per call.\nREMEMBER\nMutable default? Use None." },
  { id: 'b_py_iseq', pack: 'foundations', topic: 'python', level: 2, title: 'is vs ==', blurb: "== asks 'equal value?'. is asks 'the exact same object?'. Use == for values; reserve is for None." },
  { id: 'b_py_generator', pack: 'foundations', topic: 'python', level: 3, title: 'Generators are lazy', blurb: 'yield produces values one at a time, on demand — so you can stream millions of items without holding them all in memory.', code: 'def evens():\n    n = 0\n    while True:\n        yield n\n        n += 2', lang: 'python', detail: "YIELD, DON'T RETURN\nA function with yield returns a generator. Each next() runs to the next yield, hands back a value, and FREEZES — resuming right there next time.\nWHY LAZY WINS\nValues are produced on demand, so you can stream millions (or an infinite sequence) without ever holding them all in memory.\nONE SHOT\nA generator is exhausted after one pass — loop it twice and the second is empty. Wrap it in list() if you need to reuse the values.\nREMEMBER\nyield = produce one value at a time, on demand." },
  { id: 'b_stat_corr', pack: 'foundations', topic: 'stats', level: 1, title: "Correlation isn't causation", blurb: 'Two things moving together may share a hidden cause, or be coincidence. A correlation is a hypothesis, not a conclusion.', detail: "THE CLAIM\nTwo things moving together does NOT mean one causes the other. A correlation is evidence to investigate, not a conclusion to act on.\nTHE THIRD VARIABLE\nIce-cream sales and drownings rise together — because both follow summer heat. A hidden common cause makes unrelated things march in step.\nTHE OTHER TRAPS\nReverse causation (does X cause Y, or Y cause X?) and plain coincidence — test enough pairs and some line up by chance alone.\nESTABLISHING CAUSE\nIt takes more: a randomised experiment, or careful controls for the confounders. That is why the A/B test exists.\nREMEMBER\nCorrelation is a hypothesis; only a controlled test earns the word causes." },
  { id: 'b_stat_pvalue', pack: 'foundations', topic: 'stats', level: 3, title: 'What a p-value actually says', blurb: "It's the chance of data this extreme IF the null hypothesis were true. It is NOT the probability the null is true, and not the size of an effect.", detail: "THE DEFINITION\nA p-value is the probability of seeing data THIS extreme (or more) IF the null hypothesis were true. Small p means the data would be surprising under 'no effect'.\nWHAT IT IS NOT\nNOT the probability the null is true. NOT the probability you are wrong. NOT the size or importance of the effect.\nTHE 0.05 TRAP\np < 0.05 is a convention, not a law of nature. With enough data, trivial effects earn tiny p-values — significant does not mean important.\nREMEMBER\np = surprise under the null, nothing more." },
  { id: 'b_stat_median', pack: 'foundations', topic: 'stats', level: 1, title: 'Median shrugs off outliers', blurb: 'One billionaire wrecks the mean income of a room but barely moves the median. For skewed data, the median is the honest "typical".', detail: "THE DIFFERENCE\nThe mean adds everything and divides; the median is just the MIDDLE value. So one extreme number drags the mean but barely nudges the median.\nTHE ROOM EXAMPLE\nTen people earning 50k average 50k. Walk in a billionaire and the mean rockets past 90 million — while the median stays right around 50k. Which describes the room?\nWHEN TO USE WHICH\nSkewed data — income, house prices, response times — wants the median. Roughly symmetric data is fine with the mean, which uses every value.\nTHE TELL\nMean far above median means a long right tail, a few big values. The gap between them is itself information.\nREMEMBER\nMedian = the honest typical when outliers or skew are in play." },
  { id: 'b_cs_bigo', pack: 'foundations', topic: 'cs', level: 1, title: 'Big-O is about growth', blurb: 'It describes how work scales as input grows, ignoring constants. O(n) doubles when input doubles; O(n²) quadruples; O(log n) barely moves.' },
  { id: 'b_cs_hash', pack: 'foundations', topic: 'cs', level: 2, title: 'Hash tables are O(1) on average', blurb: 'A hash maps a key straight to a bucket, so lookup/insert average constant time — the magic behind dict and set. Worst case degrades with collisions.', detail: "THE TRICK\nA hash function turns a key into an array index directly. No searching — you COMPUTE where the value lives, so lookup and insert average O(1).\nCOLLISIONS\nTwo keys can hash to the same slot. Handle it by chaining (a little list per slot) or open addressing (probe for the next free one). A good hash keeps these rare.\nTHE WORST CASE\nIf everything collides into one slot it degrades to O(n) — a linear scan. Adversarial or terrible hashes are why it is average O(1), not guaranteed.\nRESIZING\nAs it fills (the load factor climbs) it grows and rehashes everything — an occasional expensive insert that keeps the average cheap.\nREMEMBER\nHash table = compute the slot; O(1) average, O(n) if it all collides." },
  { id: 'b_cs_idempotent', pack: 'foundations', topic: 'cs', level: 2, title: 'Idempotent = safe to retry', blurb: 'An operation you can run twice with the same result (like PUT or DELETE). It is what lets a flaky network retry without doubling the effect.' },
];

/*
 * The SQL pack — original cards covering the standard Basic-SQL curriculum
 * (SELECT · WHERE · AND/OR/NOT · BETWEEN · IN · LIKE · ORDER BY · grouping).
 * Written from scratch, not lifted from any tutorial; SQL facts, my own words.
 */
export const SQL_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_sql_what', pack: 'sql', topic: 'sql', level: 1, title: 'SQL asks questions of tables', blurb: 'SQL reads and writes relational databases — data as rows and columns. You describe WHAT you want back; the engine works out how to fetch it.' },
  { id: 'b_sql_select', pack: 'sql', topic: 'sql', level: 1, title: 'SELECT picks columns', blurb: 'Name the columns you want (or * for all of them) and the table to read from.', code: 'SELECT name, salary\nFROM employees;', lang: 'sql' },
  { id: 'b_sql_where', pack: 'sql', topic: 'sql', level: 1, title: 'WHERE filters rows', blurb: 'It keeps only rows whose condition is true. Text values go in single quotes.', code: "SELECT *\nFROM employees\nWHERE dept = 'Sales';", lang: 'sql' },
  { id: 'b_sql_andornot', pack: 'sql', topic: 'sql', level: 1, title: 'AND, OR, NOT combine conditions', blurb: 'AND needs both true, OR needs either, NOT flips one. Parenthesise to make precedence explicit.', code: "WHERE dept = 'Sales'\n  AND (salary > 50000 OR bonus > 0);", lang: 'sql' },
  { id: 'b_sql_between', pack: 'sql', topic: 'sql', level: 1, title: 'BETWEEN is an inclusive range', blurb: 'BETWEEN a AND b matches from a to b, both endpoints included. Works on numbers, dates and text.', code: 'WHERE age BETWEEN 18 AND 30;', lang: 'sql' },
  { id: 'b_sql_in', pack: 'sql', topic: 'sql', level: 1, title: 'IN matches a set', blurb: 'IN (…) is shorthand for a stack of OR-equals — cleaner than chaining them.', code: "WHERE country IN ('US', 'UK', 'CA');", lang: 'sql' },
  { id: 'b_sql_like', pack: 'sql', topic: 'sql', level: 2, title: 'LIKE matches patterns', blurb: "% stands for any run of characters, _ for exactly one. So 'A%' means starts-with-A.", code: "WHERE name LIKE 'A%'    -- starts with A\n   OR name LIKE '_o%';  -- 'o' as 2nd letter", lang: 'sql' },
  { id: 'b_sql_orderby', pack: 'sql', topic: 'sql', level: 1, title: 'ORDER BY sorts the result', blurb: 'ASC is ascending (the default), DESC descending. List several columns to sort left to right.', code: 'ORDER BY salary DESC, name ASC;', lang: 'sql' },
  { id: 'b_sql_distinct', pack: 'sql', topic: 'sql', level: 2, title: 'DISTINCT drops duplicates', blurb: 'It returns each unique row (or unique value, for a single column) — handy for "what values exist here?".', code: 'SELECT DISTINCT country\nFROM customers;', lang: 'sql' },
  { id: 'b_sql_limit', pack: 'sql', topic: 'sql', level: 1, title: 'LIMIT caps the rows', blurb: 'Return only the first N rows. Pair it with ORDER BY to get a real "top N".', code: 'SELECT name FROM players\nORDER BY score DESC\nLIMIT 10;', lang: 'sql' },
  { id: 'b_sql_null2', pack: 'sql', topic: 'sql', level: 2, title: 'Test NULL with IS, not =', blurb: "NULL means unknown, so NULL = NULL isn't true. Filter with IS NULL / IS NOT NULL.", code: 'WHERE manager_id IS NULL;', lang: 'sql' },
  { id: 'b_sql_alias', pack: 'sql', topic: 'sql', level: 2, title: 'AS renames a column or table', blurb: 'An alias gives a column a friendlier output name, or a table a short handle to use in joins.', code: 'SELECT salary * 12 AS annual_pay\nFROM employees AS e;', lang: 'sql' },
  { id: 'b_sql_groupby', pack: 'sql', topic: 'sql', level: 2, title: 'GROUP BY collapses rows into groups', blurb: 'One output row per group, with aggregates — COUNT, SUM, AVG, MIN, MAX — computed within each group.', code: 'SELECT dept, AVG(salary)\nFROM employees\nGROUP BY dept;', lang: 'sql' },
  { id: 'b_sql_having2', pack: 'sql', topic: 'sql', level: 3, title: 'HAVING filters groups', blurb: 'WHERE filters rows before grouping; HAVING filters the groups after — the only place an aggregate belongs in a filter.', code: 'GROUP BY dept\nHAVING COUNT(*) > 5;', lang: 'sql' },
  { id: 'b_sql_order_exec', pack: 'sql', topic: 'sql', level: 3, title: 'SQL runs in a different order than you write it', blurb: 'Logical order: FROM → WHERE → GROUP BY → HAVING → SELECT → ORDER BY → LIMIT. That is why a SELECT alias cannot be used back in WHERE.' },
  { id: 'b_sql_comment', pack: 'sql', topic: 'sql', level: 1, title: 'Comment with -- or /* */', blurb: '-- comments to the end of the line; /* … */ spans lines. Leave a note on the tricky bits.', code: '-- active users only\nWHERE active = 1; /* soft-deletes excluded */', lang: 'sql' },

  // ── Intermediate (level 2) ──────────────────────────────────────────
  { id: 'b_sql_innerjoin', pack: 'sql', topic: 'sql', level: 2, title: 'INNER JOIN keeps only matches', blurb: 'It returns rows where the ON condition matches in BOTH tables; unmatched rows on either side are dropped.', code: 'SELECT o.id, c.name\nFROM orders o\nJOIN customers c ON c.id = o.customer_id;', lang: 'sql' },
  { id: 'b_sql_jointypes', pack: 'sql', topic: 'sql', level: 2, title: 'Join types differ only in who survives', blurb: 'INNER = matches only. LEFT = all left rows. RIGHT = all right rows. FULL OUTER = all of both. The unmatched side fills with NULL.' },
  { id: 'b_sql_crossjoin', pack: 'sql', topic: 'sql', level: 2, title: 'CROSS JOIN pairs everything', blurb: 'Every row of A with every row of B — the Cartesian product, N×M rows. Usually a bug when it happens by accident (a forgotten ON).' },
  { id: 'b_sql_selfjoin', pack: 'sql', topic: 'sql', level: 2, title: 'A table can join itself', blurb: 'Alias it twice to relate rows within one table — an employee to their manager, say.', code: 'SELECT e.name, m.name AS manager\nFROM emp e\nJOIN emp m ON m.id = e.manager_id;', lang: 'sql' },
  { id: 'b_sql_aggregates', pack: 'sql', topic: 'sql', level: 2, title: 'Aggregates fold many rows into one', blurb: 'COUNT, SUM, AVG, MIN, MAX. With no GROUP BY they collapse the whole result to a single row.', code: 'SELECT COUNT(*), AVG(salary)\nFROM employees;', lang: 'sql' },
  { id: 'b_sql_case', pack: 'sql', topic: 'sql', level: 2, title: "CASE is SQL's if / else", blurb: 'Return a different value per row by condition. The first matching WHEN wins; ELSE is the fallback.', code: "SELECT name,\n  CASE WHEN score>=90 THEN 'A'\n       WHEN score>=80 THEN 'B'\n       ELSE 'C' END AS grade\nFROM exams;", lang: 'sql' },
  { id: 'b_sql_subquery', pack: 'sql', topic: 'sql', level: 2, title: 'A subquery is a query inside a query', blurb: 'Use its result in WHERE, SELECT, or FROM. Here it supplies the set for IN.', code: "SELECT name FROM employees\nWHERE dept_id IN (\n  SELECT id FROM depts WHERE region='EU');", lang: 'sql' },
  { id: 'b_sql_exists', pack: 'sql', topic: 'sql', level: 3, title: 'EXISTS checks for any match', blurb: 'True as soon as the subquery returns one row — often faster than IN for a correlated "has any" test.', code: 'SELECT u.name FROM users u\nWHERE EXISTS (\n  SELECT 1 FROM orders o WHERE o.uid = u.id);', lang: 'sql' },
  { id: 'b_sql_union', pack: 'sql', topic: 'sql', level: 2, title: 'UNION stacks results; ALL keeps dupes', blurb: 'UNION removes duplicate rows (and sorts to do it); UNION ALL keeps everything and is faster. Both need matching column counts and types.' },
  { id: 'b_sql_coalesce', pack: 'sql', topic: 'sql', level: 2, title: 'COALESCE returns the first non-NULL', blurb: "A clean default for missing values — it takes the first argument that isn't NULL.", code: "SELECT COALESCE(nickname, first_name, 'friend');", lang: 'sql' },
  { id: 'b_sql_nullif', pack: 'sql', topic: 'sql', level: 3, title: 'NULLIF guards division by zero', blurb: 'NULLIF(a, 0) turns 0 into NULL, so a / NULLIF(b, 0) yields NULL instead of an error.', code: 'SELECT wins * 1.0 / NULLIF(games, 0) AS win_rate;', lang: 'sql' },
  { id: 'b_sql_cast', pack: 'sql', topic: 'sql', level: 2, title: 'CAST converts types', blurb: 'Turn a string into a number, a timestamp into a date, and so on. Postgres also spells it value::type.', code: "SELECT CAST('2020-01-01' AS DATE),\n       CAST(qty AS REAL);", lang: 'sql' },
  { id: 'b_sql_strings', pack: 'sql', topic: 'sql', level: 2, title: 'The string toolkit', blurb: 'LENGTH, UPPER / LOWER, TRIM, SUBSTRING, and CONCAT (or the || operator) clean and reshape text.', code: "SELECT UPPER(TRIM(name)),\n       first || ' ' || last AS full;", lang: 'sql' },
  { id: 'b_sql_pagination', pack: 'sql', topic: 'sql', level: 2, title: 'LIMIT + OFFSET paginate', blurb: 'LIMIT 10 OFFSET 20 is page 3 at ten per page. Always pair with ORDER BY, or "page" has no stable meaning.', code: 'SELECT * FROM posts\nORDER BY created DESC\nLIMIT 10 OFFSET 20;', lang: 'sql' },

  // ── Advanced (level 3) ──────────────────────────────────────────────
  { id: 'b_sql_cte', pack: 'sql', topic: 'sql', level: 3, title: 'A CTE names a subquery', blurb: 'WITH gives a query block a name you can reuse, so a nested query reads top-to-bottom instead of inside-out.', code: 'WITH big AS (\n  SELECT dept, SUM(pay) t FROM emp GROUP BY dept)\nSELECT * FROM big WHERE t > 1000000;', lang: 'sql' },
  { id: 'b_sql_recursive', pack: 'sql', topic: 'sql', level: 3, title: 'Recursive CTEs walk hierarchies', blurb: 'WITH RECURSIVE builds on itself — org charts, graphs, number series: an anchor row, then a step that references the CTE until it stops.' },
  { id: 'b_sql_window', pack: 'sql', topic: 'sql', level: 3, title: 'Window functions keep every row', blurb: 'OVER() runs an aggregate or rank per row WITHOUT collapsing the result — unlike GROUP BY, nothing is folded away.', code: 'SELECT name, salary,\n  AVG(salary) OVER () AS company_avg\nFROM employees;', lang: 'sql' },
  { id: 'b_sql_partition', pack: 'sql', topic: 'sql', level: 3, title: 'PARTITION BY windows per group', blurb: 'Like GROUP BY, but for a window: it restarts the calculation for each partition while keeping the rows.', code: 'AVG(salary) OVER (PARTITION BY dept)', lang: 'sql' },
  { id: 'b_sql_ranks', pack: 'sql', topic: 'sql', level: 3, title: 'ROW_NUMBER vs RANK vs DENSE_RANK', blurb: 'ROW_NUMBER is always 1,2,3 (ties broken arbitrarily). RANK skips after a tie (1,1,3). DENSE_RANK does not (1,1,2).', code: 'ROW_NUMBER() OVER (ORDER BY score DESC)', lang: 'sql' },
  { id: 'b_sql_laglead', pack: 'sql', topic: 'sql', level: 3, title: 'LAG and LEAD peek at neighbours', blurb: "The previous or next row's value in the window — perfect for deltas over time.", code: 'salary - LAG(salary) OVER (ORDER BY hired)\n  AS raise;', lang: 'sql' },
  { id: 'b_sql_running', pack: 'sql', topic: 'sql', level: 3, title: 'Running totals with SUM OVER', blurb: 'An ordered window accumulates as it goes — a cumulative sum with no self-join.', code: 'SUM(amount) OVER (ORDER BY day) AS running', lang: 'sql' },
  { id: 'b_sql_btree', pack: 'sql', topic: 'sql', level: 3, title: 'Indexes are sorted shortcuts', blurb: 'A B-tree index turns a full table scan into a fast lookup for the columns you filter, join, or sort on — paid for with slower writes and storage. Index selectively.' },
  { id: 'b_sql_sargable', pack: 'sql', topic: 'sql', level: 3, title: 'Keep predicates sargable', blurb: 'Wrapping a column in a function — WHERE YEAR(d)=2020 — hides it from its index. Rewrite as a range so the index can be used.', code: "WHERE d >= '2020-01-01'\n  AND d <  '2021-01-01';", lang: 'sql' },
  { id: 'b_sql_explain', pack: 'sql', topic: 'sql', level: 3, title: 'EXPLAIN shows the plan', blurb: 'It reveals whether the engine uses an index or scans the whole table, and where the cost is. The first tool to reach for when a query is slow.', code: 'EXPLAIN ANALYZE\nSELECT * FROM orders WHERE uid = 42;', lang: 'sql' },
  { id: 'b_sql_transaction', pack: 'sql', topic: 'sql', level: 3, title: 'Transactions are all-or-nothing', blurb: 'BEGIN … COMMIT makes a group of writes atomic; ROLLBACK undoes them. ACID = Atomic, Consistent, Isolated, Durable.', code: 'BEGIN;\nUPDATE acct SET bal=bal-100 WHERE id=1;\nUPDATE acct SET bal=bal+100 WHERE id=2;\nCOMMIT;', lang: 'sql' },
  { id: 'b_sql_view', pack: 'sql', topic: 'sql', level: 3, title: 'A view is a saved query', blurb: 'SELECT from it like a table; it always reflects the live underlying data. Great for hiding complexity — a materialized view is the one that caches.', code: 'CREATE VIEW active_users AS\nSELECT * FROM users WHERE active = 1;', lang: 'sql' },
  { id: 'b_sql_selectstar', pack: 'sql', topic: 'sql', level: 2, title: 'SELECT * costs you', blurb: 'It fetches columns you do not need, breaks silently when the schema changes, and blocks index-only scans. Name the columns you actually use.' },
];

/* ── Python: basics → advanced ─────────────────────────────────────────── */
export const PYTHON_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_py_dynamic', pack: 'python', topic: 'python', level: 1, title: 'Python is dynamically typed', blurb: "A variable is just a name bound to an object; the type belongs to the object and is checked at runtime — so one name can point at an int, then a string." },
  { id: 'b_py_listtuple', pack: 'python', topic: 'python', level: 1, title: 'List mutable, tuple immutable', blurb: "[] changes in place; () can't. Use a tuple for a fixed record or a dict key, a list for a growing collection.", code: 'pt = (3, 4)      # fixed\nxs = [1, 2, 3]   # grows', lang: 'python' },
  { id: 'b_py_dict', pack: 'python', topic: 'python', level: 1, title: 'Dicts map keys to values in O(1)', blurb: 'Backed by a hash table. dict.get(k, default) avoids a KeyError when the key is missing.', code: "ages = {'ana': 30}\nages.get('bob', 0)  # 0", lang: 'python' },
  { id: 'b_py_set', pack: 'python', topic: 'python', level: 1, title: 'Sets are unique and fast to search', blurb: 'Unordered, no duplicates, O(1) membership — perfect for dedup and "have I seen this?" checks.', code: 'seen = set()\nif x not in seen:\n    seen.add(x)', lang: 'python' },
  { id: 'b_py_fstring', pack: 'python', topic: 'python', level: 1, title: 'f-strings format inline', blurb: 'Drop expressions straight into the string; :.2f, :, and friends format numbers.', code: "f'{name}: {price:.2f}'", lang: 'python' },
  { id: 'b_py_truthy', pack: 'python', topic: 'python', level: 1, title: 'Empty is falsy', blurb: "0, '', [], {} and None all count as False in an if — so `if xs:` reads as 'if non-empty'." },
  { id: 'b_py_slice', pack: 'python', topic: 'python', level: 1, title: 'Slicing takes a range', blurb: 'xs[start:stop:step], stop excluded. xs[::-1] reverses; xs[:] makes a copy.', code: 'xs[1:4]    # items 1,2,3\nxs[::-1]   # reversed', lang: 'python' },
  { id: 'b_py_argskwargs', pack: 'python', topic: 'python', level: 2, title: '*args and **kwargs catch the rest', blurb: '*args gathers extra positionals into a tuple; **kwargs gathers keyword arguments into a dict.', code: 'def f(*args, **kwargs):\n    print(args, kwargs)', lang: 'python' },
  { id: 'b_py_unpack', pack: 'python', topic: 'python', level: 2, title: 'Unpack with * to grab the middle', blurb: 'a, *mid, b = xs binds the ends and collects everything between them into a list.', code: 'first, *rest = [1, 2, 3, 4]\n# first=1, rest=[2,3,4]', lang: 'python' },
  { id: 'b_py_lambda', pack: 'python', topic: 'python', level: 2, title: 'Lambdas are one-line functions', blurb: 'Handy as a key= or with map/filter. If it needs a name or more than a line, write a def.', code: 'sorted(words, key=lambda w: len(w))', lang: 'python' },
  { id: 'b_py_exceptions', pack: 'python', topic: 'python', level: 2, title: 'try / except / else / finally', blurb: 'except catches, else runs when there was no error, finally always runs (cleanup). Catch specific types, not a bare except.', code: 'try: risky()\nexcept ValueError as e: log(e)\nfinally: close()', lang: 'python' },
  { id: 'b_py_decorator', pack: 'python', topic: 'python', level: 2, title: 'A decorator wraps a function', blurb: '@dec replaces f with dec(f) — add logging, timing or caching without touching the body.', code: '@lru_cache\ndef fib(n): ...', lang: 'python', detail: "WHAT IT DOES\n@dec above a function is just f = dec(f). The decorator takes the function and returns a NEW one that usually calls the original with extra behaviour around it.\nTHE WRAPPER\nInside, define an inner function that does something, calls f(*args, **kwargs), maybe does something after, and returns the result — logging, timing, caching, auth.\nKEEP THE IDENTITY\nWrapping hides f's name and docstring behind the wrapper's. @functools.wraps(f) on the inner copies them back.\nREMEMBER\nDecorator = a function that returns a wrapped function." },
  { id: 'b_py_zip', pack: 'python', topic: 'python', level: 2, title: 'zip walks lists in lockstep', blurb: 'It pairs items by position and stops at the shortest. dict(zip(keys, vals)) builds a dict.', code: 'for name, age in zip(names, ages):\n    ...', lang: 'python' },
  { id: 'b_py_gil', pack: 'python', topic: 'python', level: 3, title: 'The GIL serialises Python threads', blurb: 'Only one thread runs Python bytecode at a time. Threads still help I/O-bound work (they release the GIL while waiting); for CPU-bound work, use multiprocessing.', detail: "THE LOCK\nCPython lets only ONE thread run Python bytecode at a time — the Global Interpreter Lock. So threads do not give you multi-core CPU speedup.\nWHEN THREADS STILL HELP\nI/O-bound work: a thread RELEASES the GIL while it waits on a socket or disk, so others run. Great for many concurrent downloads.\nFOR CPU WORK\nUse multiprocessing (separate processes, each with its own GIL) or a native extension. The 3.13+ free-threaded build is starting to lift this.\nREMEMBER\nGIL: threads for I/O, processes for CPU." },
  { id: 'b_py_async', pack: 'python', topic: 'python', level: 3, title: 'async / await is cooperative I/O', blurb: 'An async function hands control back at each await, so one thread juggles thousands of waits (sockets, HTTP). It does not speed up CPU work.', code: 'async def get(u):\n    return await client.fetch(u)', lang: 'python', detail: "THE MODEL\nOne thread, many tasks. At each await the function VOLUNTARILY hands control back to the event loop, which runs another task while this one waits. Cooperative, not pre-emptive.\nWHY IT SCALES\nWaiting on a socket costs almost nothing here — so one thread can juggle thousands of open connections. Ideal for web servers, scrapers, API fan-out.\nIT IS NOT PARALLELISM\nStill one thread, still the GIL. Async speeds up WAITING, not computing — a CPU-heavy stretch with no await blocks the whole loop. Use processes for that.\nTHE CATCH\nasync spreads: to await something, the caller must be async too. And one blocking call — a sync request, time.sleep — stalls every task at once.\nREMEMBER\nasync = one thread yielding at each await; great for I/O, useless for CPU." },
  { id: 'b_py_dunder', pack: 'python', topic: 'python', level: 3, title: 'Dunder methods hook the syntax', blurb: '__len__ powers len(x), __eq__ powers ==, __getitem__ powers x[i]. Implement them and your object behaves like a built-in.', code: 'def __repr__(self):\n    return f"Point({self.x}, {self.y})"', lang: 'python', detail: "THE IDEA\nDouble-underscore methods let YOUR object plug into Python's built-in syntax. Define the hook and the operator just works on your type.\nTHE MAP\n__len__ powers len(x). __eq__ powers ==. __getitem__ powers x[i]. __iter__ makes it loopable. __repr__ is what the debugger shows.\nDUCK TYPING\nPython does not check your class's base type — it checks whether the dunder EXISTS. Implement the right ones and your object is a sequence, a number, a context manager.\nREPR VS STR\n__repr__ is the unambiguous, developer-facing form — aim for something you could paste back. __str__ is the pretty, user-facing one. Define __repr__ at least.\nREMEMBER\nDunders = the hooks that make your object behave like a built-in." },
  { id: 'b_py_property', pack: 'python', topic: 'python', level: 3, title: '@property makes a method look like a field', blurb: 'Compute a value on access, or validate on assignment, without changing the call site.', code: '@property\ndef area(self):\n    return self.w * self.h', lang: 'python', detail: "THE IDEA\n@property turns a method into a read like an attribute: obj.area, no parentheses. The call site stays simple while a computation or check runs behind it.\nWHY USE IT\nCompute on access (area from width times height), or validate on assignment — without breaking code that already treats it as a plain field. Start public, add a property later.\nTHE SETTER\nPair it with a matching setter to guard writes: reject a negative radius, keep two fields in sync. Omit the setter and the attribute is read-only.\nTHE PYTHONIC POINT\nIt is why Python rarely needs Java-style getters and setters up front — expose the field, and reach for @property only when you actually need the logic.\nREMEMBER\n@property = a method that reads like a field; add a setter to guard writes." },
  { id: 'b_py_dataclass', pack: 'python', topic: 'python', level: 3, title: '@dataclass writes the boilerplate', blurb: 'It generates __init__, __repr__ and __eq__ from typed fields — a record without the ceremony.', code: '@dataclass\nclass Point:\n    x: int\n    y: int', lang: 'python' },
  { id: 'b_py_copy', pack: 'python', topic: 'python', level: 3, title: 'Shallow copy shares the insides', blurb: 'list(xs) or xs[:] copies the outer list but keeps the SAME inner objects. copy.deepcopy() clones all the way down.', detail: "THE SURPRISE\nlist(xs) or xs[:] makes a NEW outer list — but the elements inside are the SAME objects. Mutate a nested list through the copy and the original changes too.\nSHALLOW VS DEEP\nShallow copies one level. copy.deepcopy() recursively clones all the way down, so the two are fully independent — at the cost of copying everything.\nWHY IT BITES\nOnly for MUTABLE, NESTED data — lists of lists, dicts of objects. A flat list of ints is fine either way, since an int cannot be mutated.\nASSIGNMENT IS NOT A COPY\nb = a does not copy at all — both names point at ONE object. That is a level below even shallow.\nREMEMBER\nAssign shares; shallow copies one level; deepcopy clones it all." },
  { id: 'b_py_gc', pack: 'python', topic: 'python', level: 3, title: 'Python frees memory by reference counting', blurb: 'An object is freed the moment its reference count hits zero; a separate cyclic collector sweeps up reference cycles. You rarely free by hand.' },
];

/* ── Algorithms & data structures: basics → advanced ───────────────────── */
export const ALGO_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_algo_bigo', pack: 'algorithms', topic: 'algo', level: 1, title: 'Big-O measures growth, not seconds', blurb: 'It is how the work scales with input size, dropping constants. O(1) < O(log n) < O(n) < O(n log n) < O(n²) < O(2ⁿ).', detail: "NOT SECONDS\nBig-O is how the work GROWS as input grows, with constants dropped. A slow O(n) can beat a fast O(n²) — but only once n is big enough.\nTHE LADDER\nO(1) < O(log n) < O(n) < O(n log n) < O(n²) < O(2ⁿ). Each jump is a different league: doubling n barely moves log, doubles n, quadruples n².\nREADING IT\nA loop is O(n). A nested loop O(n²). Halving each step is O(log n). A good sort is O(n log n).\nWHY IT MATTERS\nIt predicts which algorithm survives at scale — the difference between a query that returns and one that hangs.\nREMEMBER\nBig-O = growth rate, constants ignored." },
  { id: 'b_algo_array', pack: 'algorithms', topic: 'algo', level: 1, title: 'Arrays index in O(1), insert in O(n)', blurb: 'Contiguous memory makes x[i] instant, but inserting in the middle shifts everything after it.' },
  { id: 'b_algo_linked', pack: 'algorithms', topic: 'algo', level: 1, title: 'Linked lists insert in O(1), index in O(n)', blurb: 'Each node points to the next, so splicing is cheap — but there is no jumping; you walk from the head.' },
  { id: 'b_algo_stackqueue', pack: 'algorithms', topic: 'algo', level: 1, title: 'Stack is LIFO, queue is FIFO', blurb: 'A stack pushes and pops the same end (undo, DFS, call stack); a queue adds at the back and removes at the front (scheduling, BFS).' },
  { id: 'b_algo_binsearch', pack: 'algorithms', topic: 'algo', level: 2, title: 'Binary search halves a sorted list', blurb: 'Check the middle, throw away half, repeat — O(log n). The list MUST be sorted.', code: 'while lo <= hi:\n    mid = (lo + hi) // 2\n    if a[mid] < t: lo = mid + 1\n    else: hi = mid - 1', lang: 'python', detail: "THE MOVE\nCheck the middle. Too small? Throw away the left half. Too big? The right. Repeat — each step halves the search, so O(log n).\nTHE PRECONDITION\nThe list MUST be sorted. On unsorted data binary search is simply wrong, not just slow.\nTHE OFF-BY-ONE\nThe bugs live in the bounds: lo <= hi vs lo < hi, mid+1 vs mid. Pick one convention and hold it exactly.\nBEYOND ARRAYS\nBinary-search the ANSWER, not just an index — 'smallest capacity that works', any monotonic yes/no question.\nREMEMBER\nSorted list, check the middle, halve." },
  { id: 'b_algo_twoptr', pack: 'algorithms', topic: 'algo', level: 2, title: 'Two pointers sweep from both ends', blurb: 'On a sorted array, move a left and right pointer inward — pair sums, palindromes, dedup, all in O(n).', code: 'l, r = 0, len(a) - 1\nwhile l < r:\n    ...', lang: 'python' },
  { id: 'b_algo_sliding', pack: 'algorithms', topic: 'algo', level: 2, title: 'Sliding window reuses work', blurb: 'Grow and shrink a window over a sequence instead of re-scanning — longest substring, max subarray, all in O(n).' },
  { id: 'b_algo_sort', pack: 'algorithms', topic: 'algo', level: 2, title: 'Comparison sorts bottom out at O(n log n)', blurb: 'Merge sort is stable and uses O(n) space; quicksort is in-place but O(n²) worst case. Counting/radix beat the bound only for bounded keys.', detail: "THE LOWER BOUND\nAny sort that works by COMPARING pairs cannot beat O(n log n) — there are n! possible orders, and each yes/no comparison can only halve them.\nMERGE SORT\nSplit, sort each half, merge. Always O(n log n), STABLE, but needs O(n) extra space for the merge. The safe default when stability matters.\nQUICKSORT\nPartition around a pivot, recurse. In-place and cache-friendly, usually fastest — but a bad pivot gives O(n²), so real ones randomise or take a median-of-three.\nBEATING THE BOUND\nCounting and radix sort skip comparisons entirely, reaching O(n) — but only for bounded integer-like keys. No free lunch for arbitrary data.\nREMEMBER\nComparison sorts floor at O(n log n); merge is stable, quick is in-place." },
  { id: 'b_algo_recursion', pack: 'algorithms', topic: 'algo', level: 2, title: 'Recursion = base case + smaller subproblem', blurb: 'Every call must move toward a base case or it never stops, and each open call sits on the call stack.', code: 'def fac(n):\n    return 1 if n <= 1 else n * fac(n - 1)', lang: 'python', detail: "THE TWO PARTS\nA base case that stops, and a recursive step that calls itself on a SMALLER input, moving toward the base. Miss either and it never ends.\nTHE CALL STACK\nEvery open call sits on the stack until it returns — so depth costs memory, and too deep overflows it (Python caps around 1000).\nTHINK IN TRUST\nAssume the recursive call already works on the smaller case; just combine its result. That leap of faith is the whole skill.\nRECURSION VS LOOP\nAnything recursive can be a loop with an explicit stack — recursion is often clearer, a loop often faster and safe from overflow.\nREMEMBER\nBase case to stop, smaller call to shrink." },
  { id: 'b_algo_bst', pack: 'algorithms', topic: 'algo', level: 2, title: 'A BST keeps things sorted', blurb: 'left < node < right, so search and insert average O(log n) — but degrade to O(n) if it becomes a chain. Balanced trees (AVL, red-black) prevent that.', detail: "THE INVARIANT\nAt every node: everything in the LEFT subtree is smaller, everything RIGHT is larger. That one rule is what makes search work.\nSEARCH BY HALVING\nCompare, go left or right, repeat — each step drops half the tree, so search, insert and delete average O(log n). Binary search made into a structure.\nTHE DEGENERATE CASE\nInsert already-sorted data and the tree becomes a straight line — a linked list with O(n) everything. The invariant held; the balance did not.\nTHE FIX\nSelf-balancing trees (AVL, red-black) rotate on insert to stay short, guaranteeing O(log n). That is what a std::map or a TreeMap uses underneath.\nREMEMBER\nBST: left smaller, right larger — fast only while it stays balanced." },
  { id: 'b_algo_traversal', pack: 'algorithms', topic: 'algo', level: 2, title: 'Tree traversal: BFS vs DFS', blurb: 'BFS visits level by level with a queue; DFS goes deep first with a stack or recursion. Pre / in / post order differ only by when you visit the node.' },
  { id: 'b_algo_heap', pack: 'algorithms', topic: 'algo', level: 2, title: 'A heap gives the min or max in O(log n)', blurb: 'A binary heap keeps the smallest (or largest) at the root — the engine behind priority queues and "top K".', code: 'import heapq\nheapq.heappush(h, x)\nheapq.heappop(h)   # smallest', lang: 'python', detail: "THE SHAPE\nA binary heap is a complete tree where every parent beats its children — smallest at the root for a min-heap. Peeking the extreme is O(1).\nTHE OPERATIONS\nPush: drop the value at the end, then bubble it UP past bigger parents. Pop: take the root, move the last item to the top, sift it DOWN. Both O(log n) — the height.\nSTORED AS AN ARRAY\nNo pointers: the children of index i sit at 2i+1 and 2i+2. A heap is just an array with a rule, which is why it is compact and cache-friendly.\nWHAT IT POWERS\nPriority queues, Dijkstra's frontier, event schedulers, and top-K — keep a heap of size K and every extra element is one cheap push-then-pop.\nREMEMBER\nHeap = extreme at the root; O(1) peek, O(log n) push and pop." },
  { id: 'b_algo_graph', pack: 'algorithms', topic: 'algo', level: 2, title: 'Graphs: adjacency list vs matrix', blurb: 'A list (dict of neighbours) is compact for sparse graphs; a matrix costs O(V²) space but checks an edge in O(1).' },
  { id: 'b_algo_bfs', pack: 'algorithms', topic: 'algo', level: 2, title: 'BFS finds the shortest unweighted path', blurb: 'Explore outward level by level with a queue; the first time you reach a node is the fewest edges away.' },
  { id: 'b_algo_dp', pack: 'algorithms', topic: 'algo', level: 3, title: 'DP trades memory for repeated work', blurb: 'When subproblems overlap, solve each once and store it — memoise top-down or fill a table bottom-up. Fibonacci, knapsack, edit distance.', detail: "THE SIGNAL\nReach for DP when subproblems OVERLAP — the naive recursion recomputes the same thing exponentially (plain Fibonacci recomputes fib(3) over and over).\nTWO STYLES\nTop-down: recurse, but memoise each answer in a cache. Bottom-up: fill a table from the base cases up. Same answers, opposite direction.\nTHE RECIPE\nDefine the state (what a subproblem is), the transition (how states combine), and the base cases. Then memoise or tabulate.\nCLASSICS\nFibonacci, knapsack, edit distance, coin change, longest common subsequence.\nREMEMBER\nOverlapping subproblems? Solve each once, store it." },
  { id: 'b_algo_greedy', pack: 'algorithms', topic: 'algo', level: 3, title: 'Greedy takes the best local step', blurb: 'Pick the locally optimal choice and never look back. It only reaches the global optimum when the problem has the right structure (interval scheduling, Huffman).', detail: "THE STRATEGY\nAt each step take the choice that looks best RIGHT NOW, and never reconsider. No backtracking, no lookahead — fast and simple when it is valid.\nWHEN IT IS CORRECT\nOnly when the problem has the right structure: a local optimum that provably leads to the global one. Interval scheduling, Huffman coding and Dijkstra all qualify.\nWHEN IT FAILS\nThe 0/1 knapsack: grabbing the most valuable item first can waste the capacity a better combination needed. Greedy commits too early and cannot take it back.\nGREEDY VS DP\nWhen local choices interact, you need DP to weigh combinations. Greedy is the special case where the first good choice is always safe.\nREMEMBER\nGreedy: best local step, no regrets — right only with the right structure." },
  { id: 'b_algo_backtrack', pack: 'algorithms', topic: 'algo', level: 3, title: 'Backtracking tries, then undoes', blurb: 'Build a solution one choice at a time; when a partial choice cannot work, undo it and try the next — permutations, N-queens, sudoku.', detail: "THE PATTERN\nBuild a solution one choice at a time. When a partial choice cannot lead anywhere valid, UNDO it and try the next. A depth-first walk of the decision tree.\nTHE PRUNING\nThe power is quitting early: the moment a partial answer breaks a constraint, abandon that whole branch — everything below it goes unexplored.\nTHE CLASSICS\nN-queens (place a queen, recurse, remove it if stuck), sudoku, permutations, subset-sum. Anything that means search all valid arrangements.\nTHE COST\nWorst case it is exponential — it IS brute force, just pruned. Good constraints and a smart order are what keep it tractable.\nREMEMBER\nBacktracking = choose, recurse, undo — depth-first search with early pruning." },
  { id: 'b_algo_dijkstra', pack: 'algorithms', topic: 'algo', level: 3, title: 'Dijkstra: shortest path with weights', blurb: 'A BFS that uses a priority queue to always expand the cheapest frontier node. Requires non-negative edge weights.', detail: "THE UPGRADE FROM BFS\nBFS finds the fewest EDGES; Dijkstra finds the least total WEIGHT. It is BFS with a priority queue in place of a plain queue.\nTHE MOVE\nAlways expand the closest unvisited node next. Relax its edges — if the path through it is cheaper, lower the neighbour's distance. Repeat until all are settled.\nTHE ONCE-SETTLED RULE\nThe first time you pop a node it already has its final shortest distance, so you never revisit it. That is the guarantee the priority queue buys.\nTHE CATCH\nNon-negative weights ONLY. A negative edge breaks the once-settled promise — use Bellman-Ford there instead.\nREMEMBER\nDijkstra = BFS by priority queue; cheapest frontier first, no negative edges." },
  { id: 'b_algo_dsu', pack: 'algorithms', topic: 'algo', level: 3, title: 'Union-Find tracks connected groups', blurb: 'union() merges two sets, find() names a set — near O(1) with path compression. It detects cycles and builds MSTs (Kruskal).', detail: "THE TWO OPERATIONS\nfind(x) names the group x belongs to; union(a, b) merges two groups. Ask are these connected? by checking whether find(a) equals find(b).\nTHE STRUCTURE\nEach element points to a parent; follow the chain to a ROOT that names the set. Union simply points one root at the other.\nTHE TWO TRICKS\nPath compression flattens the chain on every find; union by rank hangs the smaller tree under the bigger. Together they make operations near-O(1), the inverse-Ackermann function.\nWHAT IT IS FOR\nCycle detection, connected components, and Kruskal's minimum spanning tree — anywhere you repeatedly merge sets and ask what is joined.\nREMEMBER\nUnion-Find = merge sets, ask connected, near-O(1) with path compression." },
  { id: 'b_algo_trie', pack: 'algorithms', topic: 'algo', level: 3, title: 'A trie stores strings by prefix', blurb: 'Each node is a character and shared prefixes share a path — autocomplete and prefix search in O(word length).' },
  { id: 'b_algo_topo', pack: 'algorithms', topic: 'algo', level: 3, title: 'Topological sort orders dependencies', blurb: 'A linear order of a DAG where every edge points forward — build order, task scheduling. It exists only if there is no cycle.' },
];

/* ── ML: intermediate → advanced (adds to the foundations ML cards) ─────── */
export const ML_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_ml_split', pack: 'ml', topic: 'ml', level: 1, title: 'Split the data three ways', blurb: 'Train to fit, validation to tune, test to judge — once. Touch the test set while tuning and your score becomes a lie.' },
  { id: 'b_ml_crossval', pack: 'ml', topic: 'ml', level: 2, title: 'Cross-validation reuses the data', blurb: 'k-fold rotates which slice is held out and averages k scores — a sturdier estimate than one split, especially on small data.' },
  { id: 'b_ml_reg', pack: 'ml', topic: 'ml', level: 2, title: 'L1 and L2 punish big weights', blurb: 'Regularisation adds a weight penalty to the loss. L2 (ridge) shrinks smoothly; L1 (lasso) drives some weights to exactly 0, selecting features.', detail: "THE IDEA\nAdd a penalty on weight size to the loss. Now the model cannot just chase the data — it must justify every large weight, so it stays simpler and generalises better.\nL2 — RIDGE\nPenalises the SQUARE of each weight. It shrinks them all smoothly toward zero but rarely to exactly zero — good when many features each help a little.\nL1 — LASSO\nPenalises the ABSOLUTE value. Its geometry drives some weights to EXACTLY zero, so it selects features and hands you a sparse, readable model.\nTHE KNOB\nA strength term (lambda) sets how hard the penalty bites. Too high underfits; too low barely regularises.\nREMEMBER\nL2 shrinks smoothly; L1 zeroes out and selects." },
  { id: 'b_ml_loss', pack: 'ml', topic: 'ml', level: 2, title: 'Pick the loss for the task', blurb: 'MSE for regression, cross-entropy for classification. The loss is what training actually minimises — match it to what you care about.' },
  { id: 'b_ml_precrecall', pack: 'ml', topic: 'ml', level: 2, title: 'Precision vs recall', blurb: 'Precision: of the ones you flagged, how many were right. Recall: of the real ones, how many you caught. Spam and cancer weight them differently.', detail: "THE TWO QUESTIONS\nPrecision: of the ones you FLAGGED, how many were right? Recall: of the REAL ones, how many did you catch?\nTHE TRADEOFF\nFlag everything and recall hits 100% but precision tanks. Flag only the sure things and precision soars but you miss cases. The threshold sets the balance.\nWHICH MATTERS\nSpam filter: precision (a real email lost to spam is worse). Cancer screen: recall (a missed tumour is worse). The cost of each mistake decides.\nREMEMBER\nPrecision = of flagged, right. Recall = of real, caught." },
  { id: 'b_ml_f1', pack: 'ml', topic: 'ml', level: 2, title: 'F1 balances precision and recall', blurb: 'The harmonic mean of the two — high only when BOTH are high. More honest than accuracy on imbalanced classes.' },
  { id: 'b_ml_roc', pack: 'ml', topic: 'ml', level: 3, title: 'ROC-AUC scores ranking, not a cutoff', blurb: 'It sweeps every threshold, plotting true-positive vs false-positive rate. AUC 0.5 is a coin flip, 1.0 is perfect separation.', detail: "THE PROBLEM WITH ACCURACY\nA single threshold hides how well a model SEPARATES the classes. Move the cutoff and precision and recall swing — accuracy alone cannot tell you the model is good.\nTHE CURVE\nROC sweeps every threshold, plotting true-positive rate against false-positive rate. Each point is one cutoff; the curve is the whole trade-off at once.\nTHE AREA\nAUC is the area under it — the probability the model ranks a random positive above a random negative. 0.5 is a coin flip, 1.0 is perfect separation.\nTHRESHOLD-FREE\nSo AUC judges the RANKING, independent of where you finally set the cutoff — pick that later from the precision and recall you need.\nREMEMBER\nAUC = how well it ranks positives over negatives, across every threshold." },
  { id: 'b_ml_confusion', pack: 'ml', topic: 'ml', level: 2, title: 'The confusion matrix shows the mistakes', blurb: 'TP, FP, FN, TN in one grid — every classification metric (accuracy, precision, recall) is just a ratio of its cells.' },
  { id: 'b_ml_scaling', pack: 'ml', topic: 'ml', level: 2, title: 'Scale features for distance and gradient models', blurb: 'If one feature runs 0–1 and another 0–100000, it dominates. Standardise or min-max — trees do not care, but KNN, SVM and neural nets do.' },
  { id: 'b_ml_onehot', pack: 'ml', topic: 'ml', level: 2, title: 'One-hot encodes categories', blurb: "Turn a category into a row of 0/1 columns so the model doesn't read 'red=1, blue=2' as an ordering.", code: 'blue → [0, 1, 0]', lang: 'text' },
  { id: 'b_ml_optimizers', pack: 'ml', topic: 'ml', level: 3, title: 'SGD, momentum, Adam', blurb: 'Plain SGD steps by the gradient; momentum carries velocity through flat spots; Adam adapts a per-parameter step size and usually just works.', detail: "PLAIN SGD\nStep downhill by the gradient times the learning rate. Simple and it works — but it crawls through flat valleys and rattles across steep, narrow ones.\nMOMENTUM\nKeep a running velocity: a decaying average of past gradients, and step by that. It powers through flat spots and damps the zig-zag, like a ball rolling downhill.\nADAM\nAdapt a PER-PARAMETER learning rate from the recent size of each gradient, plus momentum. Rarely needs tuning — the reason it is the default for most deep nets.\nTHE TRADE\nAdam converges fast and forgivingly; a well-tuned SGD with momentum sometimes generalises a touch better. Start with Adam.\nREMEMBER\nSGD steps, momentum carries, Adam adapts per weight." },
  { id: 'b_ml_vanishing', pack: 'ml', topic: 'ml', level: 3, title: 'Vanishing and exploding gradients', blurb: 'In deep nets, gradients multiply through layers and shrink to 0 or blow up. ReLU, residual connections and normalisation keep them alive.' },
  { id: 'b_ml_batchnorm', pack: 'ml', topic: 'ml', level: 3, title: 'Batch norm steadies training', blurb: "It normalises each layer's inputs per mini-batch, so you can use higher learning rates and train deeper nets faster." },
  { id: 'b_ml_pca', pack: 'ml', topic: 'ml', level: 3, title: 'PCA compresses along the biggest variance', blurb: 'It finds new axes (principal components) that capture the most spread, so you keep a few and drop the rest — reduction and visualisation.', detail: "THE IDEA\nFind new axes — principal components — along the directions the data varies MOST. Keep the first few, drop the rest: fewer dimensions, most of the information.\nHOW IT WORKS\nThe components are the eigenvectors of the covariance matrix, ordered by how much variance each captures. PC1 is the single most informative direction, PC2 the next.\nWHAT YOU GET\nCompression, denoising, and 2-D pictures of high-dimensional data. A handful of components often holds 90% or more of the variance.\nTHE CATCHES\nIt is linear (curved structure escapes it), the new axes lose their original meaning, and you must scale features first or the largest-unit one dominates.\nREMEMBER\nPCA = new axes along maximum variance; keep a few, lose little." },
  { id: 'b_ml_kmeans', pack: 'ml', topic: 'ml', level: 2, title: 'k-means clusters by nearest centroid', blurb: 'Pick k centres, assign each point to the closest, move each centre to its points’ mean, repeat. You choose k; it finds the groups.' },
  { id: 'b_ml_tree', pack: 'ml', topic: 'ml', level: 2, title: 'Decision trees split on questions', blurb: 'Each node asks a yes/no on one feature; leaves are predictions. Readable — but a deep tree overfits.' },
  { id: 'b_ml_forest', pack: 'ml', topic: 'ml', level: 2, title: 'Random forests vote', blurb: 'Many trees on random subsets of rows and features, averaged — bagging cuts the variance a single tree suffers.' },
  { id: 'b_ml_boosting', pack: 'ml', topic: 'ml', level: 3, title: 'Boosting fixes its own mistakes', blurb: 'Trees added in sequence, each focused on the errors of the last (XGBoost, LightGBM). Often the winner on tabular data.', detail: "THE IDEA\nBuild trees in SEQUENCE, each trained on what the ensemble still gets wrong. Many weak learners, corrected one after another, add up to a strong one.\nGRADIENT BOOSTING\nEach new tree fits the residual errors of the running total, then is added in at a small learning rate. Slow, deliberate steps down the loss.\nWHY IT WINS TABULAR\nXGBoost and LightGBM handle mixed features, missing values and interactions out of the box — usually the top score on spreadsheet-shaped data.\nBOOSTING VS BAGGING\nA random forest averages independent trees to cut variance. Boosting adds dependent trees to cut bias. Opposite cures, both ensembles.\nREMEMBER\nBoosting = trees in sequence, each fixing the errors of the last." },
  { id: 'b_ml_cnn', pack: 'ml', topic: 'ml', level: 3, title: 'CNNs slide filters over grids', blurb: 'A convolution reuses one small filter across an image, learning edges → shapes → objects with far fewer weights than a dense net.', detail: "THE FILTER\nA small window of weights slides across the image, taking a dot product at each spot. One filter learns one pattern — an edge, a colour blob — everywhere at once.\nWEIGHT SHARING\nThat reuse is the trick: the same few weights scan the whole image, so a CNN needs FAR fewer parameters than a dense net, and a cat is a cat wherever it sits.\nTHE HIERARCHY\nStack layers and the patterns compound: edges to textures to shapes to objects. Pooling shrinks the grid between layers, widening what each filter sees.\nWHERE IT FITS\nAnything with grid structure and local patterns — images above all, but also audio spectrograms and board positions.\nREMEMBER\nCNN = one small filter, reused across the grid, stacked into a hierarchy." },
  { id: 'b_ml_transfer', pack: 'ml', topic: 'ml', level: 3, title: 'Transfer learning reuses a trained model', blurb: 'Start from a big pretrained model and fine-tune on your small dataset — you inherit its features instead of learning from scratch.' },
];

/* ── AI / LLMs: adds to the foundations AI cards ────────────────────────── */
export const AI_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_ai_context', pack: 'ai', topic: 'ai', level: 1, title: 'The context window is working memory', blurb: 'Everything the model sees at once — prompt, history, retrieved docs — measured in tokens. Past the limit, the oldest falls off.' },
  { id: 'b_ai_prompt', pack: 'ai', topic: 'ai', level: 1, title: 'Prompting is programming in English', blurb: 'Be specific, state the format you want, show an example. Clear instructions beat clever tricks.' },
  { id: 'b_ai_system', pack: 'ai', topic: 'ai', level: 1, title: 'The system prompt sets the rules', blurb: "A high-priority instruction that frames the model's role and boundaries for the whole conversation, above the user's turns." },
  { id: 'b_ai_fewshot', pack: 'ai', topic: 'ai', level: 2, title: 'Few-shot = teach by examples', blurb: 'Put a couple of input→output examples in the prompt and the model imitates the pattern — no training needed (in-context learning).' },
  { id: 'b_ai_cot', pack: 'ai', topic: 'ai', level: 2, title: 'Chain-of-thought = ask it to reason', blurb: 'Telling the model to work step by step before answering improves hard reasoning, because each step conditions the next.', detail: "THE TRICK\nTell the model to work through the steps BEFORE giving the answer. Prompting it to think step by step turns a wrong snap answer into a right, reasoned one.\nWHY IT WORKS\nEach token conditions the next, so writing the intermediate steps gives the model more room to compute — it reasons INTO the answer instead of guessing it.\nWHERE IT HELPS\nMulti-step arithmetic, logic, word problems — anything where the answer depends on a chain. Little help on simple recall.\nTHE MODERN TWIST\nReasoning models are TRAINED to do this internally, so you need not always ask — but seeing the work still helps you catch a bad step.\nREMEMBER\nChain-of-thought = reason step by step, because each step conditions the next." },
  { id: 'b_ai_rag', pack: 'ai', topic: 'ai', level: 2, title: 'RAG grounds answers in your data', blurb: 'Retrieve relevant documents, put them in the prompt, then answer FROM them — cuts hallucination and adds fresh, private knowledge without retraining.', detail: "THE PROBLEM\nAn LLM only knows its training data — frozen and public. It cannot cite your private docs, and it invents when unsure.\nTHE FIX\nRetrieve the relevant chunks (usually by embedding similarity), paste them into the prompt, and instruct the model to answer FROM them. Knowledge without retraining.\nTHE PIPELINE\nAhead of time: chunk your docs, embed each, store in a vector DB. At query time: embed the question, fetch the nearest chunks, prompt with them, answer.\nWHY IT WINS\nFresh (update the DB, not the model), private, cheaper than fine-tuning — and you can show the sources.\nREMEMBER\nRAG = retrieve, stuff the prompt, answer from it." },
  { id: 'b_ai_embed', pack: 'ai', topic: 'ai', level: 2, title: 'Embeddings turn text into vectors', blurb: "Similar meanings land near each other in vector space, so nearest-neighbour search becomes semantic search — the engine behind RAG.", detail: "THE IDEA\nA model maps text to a point in high-dimensional space where MEANING is the geometry — similar meanings land close, regardless of the exact words.\nSEMANTIC SEARCH\nSo 'car' sits near 'automobile'. Search becomes find the nearest vectors, not match the keywords — the engine under RAG and recommendations.\nCOSINE SIMILARITY\nCloseness is usually the angle between vectors (cosine): 1 is identical direction, 0 unrelated. Magnitude is ignored.\nREMEMBER\nEmbedding = meaning as coordinates; near = similar." },
  { id: 'b_ai_topp', pack: 'ai', topic: 'ai', level: 2, title: 'top-p and top-k trim the choices', blurb: 'Beyond temperature, sample only from the top-k tokens or the smallest set covering probability p — fewer wild picks.' },
  { id: 'b_ai_pretrain', pack: 'ai', topic: 'ai', level: 2, title: 'Pretraining, then fine-tuning', blurb: 'First learn language from a huge corpus (self-supervised next-token), then specialise on a smaller labelled set. Most of the knowledge is in stage one.' },
  { id: 'b_ai_finetune', pack: 'ai', topic: 'ai', level: 3, title: 'Fine-tune vs prompt', blurb: 'Prompting and RAG change what the model SEES; fine-tuning changes its WEIGHTS. Fine-tune for style and format at scale — for facts, reach for RAG.', detail: "TWO DIFFERENT LEVERS\nPrompting and RAG change what the model SEES at inference. Fine-tuning changes its WEIGHTS by training on your examples. One is context; the other is the model itself.\nWHAT FINE-TUNING IS FOR\nTeaching a STYLE, format or behaviour you cannot easily describe — a house voice, a strict output shape, a niche task — by showing hundreds to thousands of examples.\nWHAT IT IS BAD AT\nFacts. Bake a fact into the weights and it is frozen and untraceable; the model still cannot cite it and it goes stale. For knowledge, reach for RAG.\nTHE ORDER TO TRY\nPrompt first. Then few-shot. Then RAG for knowledge. Fine-tune last, when the cheaper levers run out — it is the most work to build and keep current.\nREMEMBER\nFine-tune for behaviour, RAG for knowledge, prompt before both." },
  { id: 'b_ai_rlhf', pack: 'ai', topic: 'ai', level: 3, title: 'RLHF aligns to human preference', blurb: 'After pretraining, the model is tuned on human rankings of its answers, so it becomes helpful and follows instructions — not just a next-token predictor.', detail: "THE GAP IT CLOSES\nA pretrained model predicts likely text — not necessarily HELPFUL text. RLHF is the step that turns a raw next-token predictor into an assistant that follows instructions.\nHOW IT WORKS\nHumans rank model answers best to worst. Those rankings train a reward model, and the LLM is then optimised to score high on it — learning what people actually prefer.\nTHE RESULT\nHelpfulness, harmlessness, instruction-following — the assistant personality. Most of the knowledge came from pretraining; RLHF shapes the behaviour around it.\nTHE COUSINS\nDPO and similar methods reach the same goal more directly from preference pairs, skipping the separate reward model.\nREMEMBER\nRLHF = rank answers, train a reward, tune the model to please it." },
  { id: 'b_ai_agents', pack: 'ai', topic: 'ai', level: 3, title: 'Agents call tools in a loop', blurb: 'Give the model tools (search, code, APIs) and let it decide, act, observe the result, and repeat — reasoning plus doing.', detail: "THE LOOP\nGive the model tools — search, code, APIs — and let it run: decide an action, call the tool, OBSERVE the result, decide again. Reasoning plus doing, until the task is done.\nWHY TOOLS\nThe model's own knowledge is frozen and it cannot act on the world. A tool call fetches fresh data or causes a real effect, then feeds the result back into the next step.\nTHE INGREDIENTS\nA goal, a set of tools with clear descriptions, and a stopping condition. The model plans, acts, and adapts to what each result tells it.\nTHE FAILURE MODES\nLoops that never stop, wrong tool choices, small errors compounding over a long chain. Guardrails and a step budget keep it honest.\nREMEMBER\nAgent = decide, act, observe, repeat — an LLM with tools and a loop." },
  { id: 'b_ai_diffusion', pack: 'ai', topic: 'ai', level: 3, title: 'Diffusion models denoise into images', blurb: 'Train a net to remove a little noise, then run it backwards from pure noise step by step until an image appears — the idea behind Stable Diffusion.', detail: "THE TRAINING\nTake a real image, add a little random noise, and train a network to predict and remove it — across every noise level, from a faint haze to pure static.\nTHE GENERATION\nNow run it BACKWARD: start from pure noise and denoise step by step. Each pass sharpens the picture a little, until a coherent image emerges from the static.\nSTEERING IT\nA text prompt conditions each step, pulling the denoising toward the words you gave. That is how Stable Diffusion and its kin turn text into pictures.\nTHE TRADE\nMany small steps make it slow but remarkably stable and controllable — the reason diffusion overtook the older one-shot image generators.\nREMEMBER\nDiffusion = learn to remove noise, then run it backward from static." },
  { id: 'b_ai_quant', pack: 'ai', topic: 'ai', level: 3, title: 'Quantisation shrinks the model', blurb: 'Store weights in 8- or 4-bit instead of 16/32, cutting memory and speeding inference for a small accuracy hit — how big models run on a laptop.' },
];

/* ── CS fundamentals: adds to the foundations CS cards ──────────────────── */
export const CS_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  { id: 'b_cs_status', pack: 'cs', topic: 'cs', level: 1, title: 'HTTP status codes by the hundreds', blurb: '2xx success, 3xx redirect, 4xx you messed up (404 not found, 401 unauthorised), 5xx the server did.' },
  { id: 'b_cs_http', pack: 'cs', topic: 'cs', level: 1, title: 'HTTP verbs say what you are doing', blurb: 'GET reads, POST creates, PUT/PATCH updates, DELETE removes. GET and DELETE should be idempotent; POST usually is not.' },
  { id: 'b_cs_dns', pack: 'cs', topic: 'cs', level: 1, title: 'DNS is the internet phone book', blurb: 'It turns a name (example.com) into an IP address, cached at many layers so it is fast — the first step of almost every request.' },
  { id: 'b_cs_stackheap', pack: 'cs', topic: 'cs', level: 2, title: 'Stack memory vs heap memory', blurb: 'The stack holds call frames and locals (fast, freed automatically on return); the heap holds objects that outlive a call. Deep recursion overflows the stack.', detail: "THE STACK\nEach function call pushes a FRAME — its locals and return address. Return, and the frame pops automatically. Fast (just move a pointer) and perfectly ordered, but small.\nTHE HEAP\nFor objects that must OUTLIVE the call that made them, or whose size is not known up front. You or the garbage collector manage their lifetime. Bigger, flexible, slower.\nWHY IT MATTERS\nDeep or infinite recursion piles up frames and overflows the stack. Objects that escape a function must live on the heap. The split explains both crashes and lifetimes.\nMANAGED LANGUAGES\nPython and Java put almost every object on the heap and a GC frees it; the stack still holds the call frames and the references into the heap.\nREMEMBER\nStack: call frames, auto-freed, tiny. Heap: long-lived objects, managed." },
  { id: 'b_cs_procthread', pack: 'cs', topic: 'cs', level: 2, title: 'Processes are isolated; threads share', blurb: 'Each process has its own memory; threads inside one share it — cheaper to switch, but you must guard shared state with locks against races.', detail: "THE DIVIDE\nA process owns its own private memory. Threads live INSIDE a process and share that memory. That one difference drives every trade-off below.\nTHREADS\nCheap to create and switch, and they share data directly — but that sharing is the danger: two threads touching one variable can race, so you reach for locks.\nPROCESSES\nIsolated, so one crashing cannot corrupt a sibling — but talking between them needs real IPC (pipes, sockets, queues), and they cost more to spin up.\nTHE RACE\nShared mutable state without a lock is the classic bug: interleaved reads and writes give a different answer each run. Lock it, or do not share it.\nREMEMBER\nThreads share memory (fast, racy); processes isolate it (safe, costlier)." },
  { id: 'b_cs_concpar', pack: 'cs', topic: 'cs', level: 2, title: 'Concurrency vs parallelism', blurb: 'Concurrency is dealing with many things at once (interleaving); parallelism is doing many at once (multiple cores). You can have either without the other.', detail: "THE DEFINITIONS\nConcurrency is DEALING with many things at once — interleaving tasks on one core. Parallelism is DOING many at once — truly simultaneous on multiple cores.\nTHE CHEF ANALOGY\nOne chef juggling several dishes is concurrent. Several chefs cooking at the same time is parallel. You can have either without the other.\nIN PRACTICE\nAn async single thread is concurrent, not parallel. Python threads are concurrent (the GIL) but not CPU-parallel. Multiprocessing is genuinely parallel.\nREMEMBER\nConcurrency = structure (juggling). Parallelism = execution (simultaneous)." },
  { id: 'b_cs_tcpudp', pack: 'cs', topic: 'cs', level: 2, title: 'TCP is reliable, UDP is fast', blurb: 'TCP guarantees ordered, retried delivery (web, files); UDP just fires packets and forgets (games, video, DNS) — no handshake, no resend.', detail: "TCP\nA handshake, then ordered, acknowledged, retried delivery. Nothing arrives out of order or missing — at the cost of round-trips and buffering. Web, files, email.\nUDP\nFire a packet and forget: no handshake, no ordering, no resend. Lower latency, but you handle any loss yourself. Games, live video, DNS.\nTHE TRADEOFF\nReliability costs time. Pick TCP when every byte must arrive; UDP when late data is worthless — a stale video frame is better dropped than resent.\nREMEMBER\nTCP: reliable, ordered, slower. UDP: fast, lossy." },
  { id: 'b_cs_rest', pack: 'cs', topic: 'cs', level: 2, title: 'REST models URLs as resources', blurb: 'Nouns as paths (/users/42), verbs as HTTP methods, stateless requests. Predictable and cacheable.' },
  { id: 'b_cs_cache', pack: 'cs', topic: 'cs', level: 2, title: 'Caching trades freshness for speed', blurb: 'Keep a copy close (memory, CDN) so you do not recompute or refetch. The hard parts are invalidation and staleness.', detail: "THE BARGAIN\nKeep a copy of an expensive result somewhere CLOSE — memory, a CDN, the browser — so you skip the recompute or the round-trip next time. Speed bought with a copy.\nWHERE IT LIVES\nLayered: CPU caches, app memory, Redis, the CDN edge, the browser. A request that hits an early layer never troubles the slow ones behind it.\nTHE HARD PART\nInvalidation. A cache holds an OLD answer while the truth moves on. Deciding when a copy is too stale to trust is famously one of the hard problems.\nTHE TOOLS\nA TTL expires entries after a set time; explicit invalidation clears them the moment the source changes. Choose by how much a stale answer costs you here.\nREMEMBER\nCache = a close copy; the price is staleness and knowing when to drop it." },
  { id: 'b_cs_latency', pack: 'cs', topic: 'cs', level: 2, title: 'Know the latency ladder', blurb: 'Roughly: RAM ~100ns, SSD ~100µs, a network round-trip ~1–100ms. Each rung is about 1000× slower — design to stay on the fast ones.', detail: "THE NUMBERS\nRoughly: RAM about 100 nanoseconds, SSD about 100 microseconds, a network round-trip about 1 to 100 milliseconds. Learn the ORDERS of magnitude, not the digits.\nEACH RUNG ~1000×\nRAM to SSD is about 1000 times slower; SSD to network more again. Every step down the ladder is a different world, and crossing one dominates everything above it.\nTHE DESIGN LESSON\nSpeed is mostly about WHICH rung you are on. Batch to turn many round-trips into one; cache to stay in memory; keep the network out of a hot loop.\nHUMAN SCALE\nScale a nanosecond up to a second and it gets visceral: RAM is a couple of minutes, an SSD read is over a day, a network round-trip is months. That is why we cache.\nREMEMBER\nRAM ≪ SSD ≪ network, about 1000× a rung — stay high on the ladder." },
  { id: 'b_cs_acid', pack: 'cs', topic: 'cs', level: 2, title: 'ACID is a transaction promise', blurb: 'Atomic (all or nothing), Consistent (valid state), Isolated (as if alone), Durable (survives a crash). SQL databases give you this.', detail: "ATOMIC\nAll or nothing. The classic transfer — debit one account, credit another — does both or neither. No half-done state survives a failure.\nCONSISTENT\nA transaction moves the database from one VALID state to another; constraints, keys and rules hold at every commit. It cannot leave rubbish behind.\nISOLATED\nConcurrent transactions do not see each other's half-finished work — each runs AS IF alone. Isolation levels tune how strictly, trading a little safety for speed.\nDURABLE\nOnce committed, it STAYS — through a crash or a power cut. The write is on disk or in a log, not only in memory.\nREMEMBER\nACID = Atomic, Consistent, Isolated, Durable — the transaction promise." },
  { id: 'b_cs_cap', pack: 'cs', topic: 'cs', level: 3, title: 'CAP: pick two under a partition', blurb: 'When the network splits, a distributed store can stay Consistent or Available, not both. Most choose availability plus eventual consistency.', detail: "THE SETUP\nIn a distributed store a network partition WILL happen — nodes cannot talk. CAP says: during a partition you get Consistency OR Availability, not both.\nTHE CHOICE\nStay Consistent, and refuse or block requests you cannot confirm (CP). Stay Available, and answer from what you have, risking stale data (AP).\nTHE REALITY\n'Pick 2 of 3' is a simplification — partitions are not optional, so it is really C vs A when one strikes. Most web systems choose AP plus eventual consistency.\nREMEMBER\nUnder a partition: consistent or available — choose one." },
  { id: 'b_cs_loadbalance', pack: 'cs', topic: 'cs', level: 2, title: 'Load balancers spread traffic', blurb: 'One entry point fans requests across many servers (round-robin, least-connections), so you scale out and survive a node dying.' },
  { id: 'b_cs_compinterp', pack: 'cs', topic: 'cs', level: 2, title: 'Compiled vs interpreted', blurb: 'A compiler translates the whole program to machine code ahead of time (C, Rust — fast); an interpreter runs it line by line (Python — flexible). A JIT does both.' },
  { id: 'b_cs_gc', pack: 'cs', topic: 'cs', level: 2, title: 'Garbage collection frees unused memory', blurb: 'The runtime finds objects nothing points at and reclaims them, so you do not free by hand — at the cost of occasional pauses.' },
  { id: 'b_cs_unicode', pack: 'cs', topic: 'cs', level: 2, title: 'UTF-8 encodes every character', blurb: 'Unicode gives each character a number; UTF-8 stores it in 1–4 bytes and stays ASCII-compatible. Length in bytes is not length in characters.' },
];

/*
 * The SQL Tutorial pack — a full basics → intermediate → advanced curriculum,
 * mapped one concept at a time from a personal study set. Original flashcard
 * phrasing (concept → title + intuition + tiny example), not tutorial prose.
 * ids `b_sqt_*`; topic 'sql'; level 1 basic · 2 intermediate · 3 advanced.
 */
export const SQL_TUTORIAL_BYTES: Omit<ByteCard, 'updatedAt'>[] = [
  // ── basics ──
  { id: 'b_sqt_rdbms', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'SQL runs on a relational database', blurb: 'An RDBMS stores data as tables of typed rows and columns with keys. SQL is how you query it — declarative: you say what you want, not how to fetch it.' },
  { id: 'b_sqt_flavors', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'One SQL, many dialects', blurb: 'PostgreSQL, MySQL, SQLite and SQL Server share a common core but differ in functions and quirks. Learn one (PostgreSQL is a solid default) and the rest transfer.' },
  { id: 'b_sqt_select', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'SELECT names the columns', blurb: 'List the columns you want and the table to read from. The database hands back a result set — a table of just those columns.', code: 'SELECT first_name, salary\nFROM employees;', lang: 'sql' },
  { id: 'b_sqt_trailingcomma', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'The trailing-comma error', blurb: 'A comma after the last column before FROM is a syntax error — SQL expects another column name. It bites when you delete the final field.', code: 'SELECT name, salary,   -- stray comma\nFROM employees;', lang: 'sql' },
  { id: 'b_sqt_selectstar', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'SELECT * is convenient, not clean', blurb: '* returns every column — fine while exploring, but wasteful and fragile in real queries. Name the columns you actually use.', code: 'SELECT * FROM employees;   -- exploring only', lang: 'sql' },
  { id: 'b_sqt_where_ops', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'WHERE compares with operators', blurb: "= equals, <> (or !=) not-equals, and < <= > >= for ordering. Strings and dates go in single quotes.", code: "SELECT *\nFROM orders\nWHERE total >= 100 AND status <> 'void';", lang: 'sql' },
  { id: 'b_sqt_andornot', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'AND binds tighter than OR', blurb: 'In a mixed condition AND is evaluated before OR — so wrap OR groups in parentheses to get the logic you mean.', code: "WHERE country = 'US'\n  AND (plan = 'pro' OR plan = 'team');", lang: 'sql' },
  { id: 'b_sqt_notbetween', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'NOT negates a condition', blurb: 'Put NOT before a predicate to flip it: NOT IN, NOT LIKE, NOT BETWEEN — it keeps the rows the plain version would drop.', code: 'WHERE age NOT BETWEEN 18 AND 30;', lang: 'sql' },
  { id: 'b_sqt_between', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'BETWEEN includes both ends', blurb: "x BETWEEN a AND b means a <= x <= b — both bounds count. Careful with timestamps: an end at midnight excludes that whole day.", code: "WHERE hired BETWEEN '2024-01-01' AND '2024-12-31';", lang: 'sql' },
  { id: 'b_sqt_in', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'IN is OR, shortened', blurb: 'value IN (a, b, c) matches any item in the list — cleaner than chaining ORs. The list can even be a subquery.', code: "WHERE country IN ('US', 'CA', 'MX');", lang: 'sql' },
  { id: 'b_sqt_like', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'LIKE matches patterns', blurb: "% is any run of characters, _ is exactly one. 'A%' starts with A; '%@gmail.com' ends with it; '_a%' has a as the 2nd char.", code: "WHERE email LIKE '%@gmail.com';", lang: 'sql' },
  { id: 'b_sqt_filter5', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'Five ways to filter in WHERE', blurb: 'Comparisons (=, >), BETWEEN for ranges, IN for lists, LIKE for patterns, and AND/OR/NOT to combine. Most filters are a mix of these five.' },
  { id: 'b_sqt_orderby', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'ORDER BY sorts the result', blurb: 'Ascending by default; add DESC for high-to-low. List several keys to break ties left to right.', code: 'ORDER BY dept ASC, salary DESC;', lang: 'sql' },
  { id: 'b_sqt_orderby_num', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'ORDER BY can use column position', blurb: "ORDER BY 2 sorts by the 2nd selected column — handy for expressions you'd rather not retype, though names read clearer.", code: 'SELECT dept, COUNT(*)\nFROM emp GROUP BY dept\nORDER BY 2 DESC;', lang: 'sql' },
  { id: 'b_sqt_limit_offset', pack: 'sql-tutorial', topic: 'sql', level: 1, title: 'LIMIT caps rows, OFFSET skips them', blurb: 'LIMIT n returns the first n rows after sorting; OFFSET m skips m first. Together they page through results.', code: 'ORDER BY score DESC\nLIMIT 10 OFFSET 20;   -- page 3', lang: 'sql' },
  // ── intermediate ──
  { id: 'b_sqt_count', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'COUNT(*) vs COUNT(col)', blurb: 'COUNT(*) counts rows. COUNT(col) counts only rows where col is not NULL. COUNT(DISTINCT col) counts unique non-null values.', code: 'SELECT COUNT(*), COUNT(DISTINCT dept)\nFROM employees;', lang: 'sql', detail: "THREE COUNTS\nCOUNT(*) is rows. COUNT(col) is rows where col is not NULL. COUNT(DISTINCT col) is unique non-null values. Three different questions.\n```sql\nSELECT\n  COUNT(*)             AS rows,\n  COUNT(manager_id)    AS have_manager,\n  COUNT(DISTINCT dept) AS depts\nFROM employees;\n```\nTHE NULL SUBTLETY\nCOUNT(col) skips NULLs — so COUNT(*) minus COUNT(col) is exactly the NULLs in col. Sometimes that gap is the answer.\nCONDITIONAL COUNT\nCOUNT(CASE WHEN paid THEN 1 END) counts only matching rows — the ELSE is NULL, which COUNT skips.\nREMEMBER\nCOUNT(*) rows · COUNT(col) non-nulls · DISTINCT uniques." },
  { id: 'b_sqt_sumavg', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'SUM and AVG ignore NULLs', blurb: 'Aggregates skip NULLs — so AVG divides by the count of non-null values, not total rows. COALESCE to 0 first if you want them counted.', code: 'SELECT SUM(amount), AVG(amount)\nFROM sales;', lang: 'sql' },
  { id: 'b_sqt_minmax', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'MIN and MAX work on any orderable type', blurb: 'Smallest and largest — numbers, dates, even text (alphabetical). The go-to for earliest/latest date or cheapest/priciest item.', code: 'SELECT MIN(hired), MAX(salary)\nFROM employees;', lang: 'sql' },
  { id: 'b_sqt_groupby', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'GROUP BY collapses rows into buckets', blurb: 'It folds rows sharing a value into one group, so aggregates run per group instead of over the whole table.', code: 'SELECT dept, AVG(salary)\nFROM employees\nGROUP BY dept;', lang: 'sql', diagram: 'Sales  100 ┐\nSales  140 ┘→ Sales  120\nEng    90   → Eng     90' },
  { id: 'b_sqt_groupby_rule', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'Every plain column must be grouped', blurb: "In a GROUP BY query each selected column is either in GROUP BY or inside an aggregate — otherwise which row's value would it show?" },
  { id: 'b_sqt_having', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'HAVING filters groups, WHERE filters rows', blurb: "WHERE runs before grouping (no aggregates allowed); HAVING runs after, on the grouped result — that's where COUNT(*) > 5 goes.", code: 'GROUP BY dept\nHAVING COUNT(*) > 5;', lang: 'sql', detail: "THE ORDER\nWHERE runs BEFORE grouping, on raw rows. HAVING runs AFTER, on the grouped result. That is the whole distinction.\nWHY IT EXISTS\nYou cannot put an aggregate in WHERE — the groups do not exist yet. HAVING is where a filter like COUNT(*) > 5 lives.\n```sql\nSELECT dept, COUNT(*)\nFROM emp\nWHERE active          -- rows first\nGROUP BY dept\nHAVING COUNT(*) > 5;  -- then groups\n```\nUSE BOTH\nWHERE to cut rows cheaply before grouping, HAVING to cut groups after.\nREMEMBER\nWHERE filters rows. HAVING filters groups." },
  { id: 'b_sqt_distinct', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'DISTINCT dedupes whole rows', blurb: 'It dedupes across ALL selected columns, not just the first — SELECT DISTINCT a, b keeps unique (a, b) pairs.', code: 'SELECT DISTINCT city, country\nFROM customers;', lang: 'sql' },
  { id: 'b_sqt_arithmetic', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'Compute new columns inline', blurb: '+, -, *, / work on columns row by row. Name the result with AS so it has a clean header.', code: 'SELECT price * quantity AS revenue\nFROM line_items;', lang: 'sql' },
  { id: 'b_sqt_intdiv', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'Integer / integer truncates', blurb: '5 / 2 is 2, not 2.5 — dividing two integers drops the remainder. Cast one side to decimal for real division.', code: 'SELECT wins * 1.0 / games AS win_rate\nFROM teams;', lang: 'sql' },
  { id: 'b_sqt_mathfns', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'The everyday math functions', blurb: "ROUND(x, d), CEIL/FLOOR, ABS, POWER(b, e), SQRT, and MOD(a, b) for remainder. ROUND's second arg is decimal places.", code: 'SELECT ROUND(avg_score, 1), MOD(id, 2)\nFROM results;', lang: 'sql' },
  { id: 'b_sqt_null', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'NULL is contagious', blurb: 'Any arithmetic or comparison with NULL yields NULL, not true/false. Test membership with IS NULL / IS NOT NULL only.', code: 'WHERE manager_id IS NULL;', lang: 'sql', detail: "NULL IS UNKNOWN\nNot zero, not empty string — it means we do not know. So NULL = NULL is not true; it is NULL. Any comparison with NULL is NULL.\nIT SPREADS\n1 + NULL is NULL. Concatenating with NULL is NULL. One NULL can quietly poison a computed column across the row.\nTESTING IT\nOnly IS NULL / IS NOT NULL work. Writing = NULL silently matches nothing.\n```sql\nWHERE manager_id IS NULL;   -- the top of the org chart\n```\nTHREE-VALUED LOGIC\nA condition is true, false, OR null. WHERE keeps only TRUE — so a NULL condition drops the row.\nREMEMBER\nCompare NULL with IS, never =." },
  { id: 'b_sqt_coalesce', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'COALESCE picks the first non-NULL', blurb: "COALESCE(a, b, c) returns the first argument that isn't NULL — the clean way to supply a default for missing data.", code: "SELECT COALESCE(nickname, first_name, 'friend')\nFROM users;", lang: 'sql', detail: "WHAT IT DOES\nCOALESCE(a, b, c, ...) returns the first argument that is not NULL — a tidy fallback chain.\nEVERYDAY USES\nA display default, treating missing numbers as 0 in a sum, or filling the NULLs a LEFT JOIN leaves behind.\n```sql\nSELECT SUM(COALESCE(bonus, 0))   -- NULLs count as 0\nFROM staff;\n```\nCOALESCE vs NULLIF\nCOALESCE turns NULL into a value; NULLIF(a, b) turns a value INTO NULL when a equals b — handy to dodge divide-by-zero.\nREMEMBER\nCOALESCE: the first non-NULL wins." },
  { id: 'b_sqt_case', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'CASE is if/else in SQL', blurb: 'It returns a value per row, testing conditions top to bottom and stopping at the first match; ELSE catches the rest.', code: "SELECT name,\n  CASE WHEN score >= 90 THEN 'A'\n       WHEN score >= 80 THEN 'B'\n       ELSE 'C' END AS grade\nFROM exams;", lang: 'sql', detail: "IF/ELSE PER ROW\nCASE tests conditions top to bottom, stops at the first true one, returns its THEN value; ELSE catches the rest (NULL if you omit it).\n```sql\nCASE WHEN score >= 90 THEN 'A'\n     WHEN score >= 80 THEN 'B'\n     ELSE 'C' END\n```\nIT IS AN EXPRESSION\nSo it goes anywhere a value goes — SELECT, ORDER BY, even inside SUM for conditional counting: SUM(CASE WHEN paid THEN 1 ELSE 0 END).\nORDER MATTERS\nIt stops at the first match, so put the tighter conditions first — 90 before 80.\nREMEMBER\nCASE: the first matching WHEN wins." },
  { id: 'b_sqt_innerjoin', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'INNER JOIN keeps only matches', blurb: 'It returns rows that pair up on the join key in both tables; unmatched rows on either side are dropped.', code: 'SELECT o.id, c.name\nFROM orders o\nJOIN customers c ON c.id = o.customer_id;', lang: 'sql', detail: "WHAT IT DOES\nPairs each left row with matching right rows on the ON condition. No match on EITHER side, and that row vanishes.\nTHE SHAPE\nRows shrink or explode: one order with one customer gives one row; a customer with no orders is gone; an order matching two customers gives two rows.\nALWAYS ALIAS\nGive each table a short alias and qualify columns (o.id, c.name) — clearer, and it avoids ambiguous-column errors.\n```sql\nSELECT o.id, c.name\nFROM orders o\nJOIN customers c ON c.id = o.customer_id;\n```\nREMEMBER\nINNER JOIN keeps only the matches, from both sides." },
  { id: 'b_sqt_leftright', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'LEFT/RIGHT JOIN keep one side whole', blurb: 'LEFT JOIN keeps every left row, NULL-filling missing right matches (RIGHT is the mirror). WHERE right.key IS NULL finds non-matches.', code: 'FROM customers c\nLEFT JOIN orders o ON o.customer_id = c.id;', lang: 'sql', diagram: 'customers    orders\n [Ann] ─────── [#1]\n [Ben] ─────── [#2]\n [Cy]  ─────── (null)  ← kept, no match', detail: "THE RULE\nLEFT JOIN keeps EVERY left row. Where the right has no match, its columns come back NULL. RIGHT JOIN is the mirror — just flip the tables.\nTHE ANTI-JOIN\nWant left rows with NO right match? LEFT JOIN, then WHERE right.key IS NULL. Customers who never ordered, in one query.\n```sql\nSELECT c.name\nFROM customers c\nLEFT JOIN orders o ON o.customer_id = c.id\nWHERE o.id IS NULL;\n```\nTHE TRAP\nA right-table condition in WHERE turns a LEFT JOIN back into an INNER one (the NULLs fail it). Put that condition in the ON clause instead.\nREMEMBER\nLEFT JOIN never drops a left row." },
  { id: 'b_sqt_fullouter', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'FULL OUTER JOIN keeps both sides', blurb: "Every row from left and right appears; wherever there's no match, the other side is NULL. Use it to reconcile two sets.", code: 'FROM a\nFULL OUTER JOIN b ON a.id = b.id;', lang: 'sql', detail: "WHAT IT DOES\nEvery row from both sides appears. Matched rows join; unmatched rows on either side come back with NULLs for the missing half.\nWHEN TO USE\nReconciling two sets — which ids are in A only, B only, or both. FULL OUTER JOIN, then check which side is NULL.\n```sql\nSELECT COALESCE(a.id, b.id) AS id\nFROM a\nFULL OUTER JOIN b ON a.id = b.id;\n```\nREMEMBER\nFULL OUTER is LEFT plus RIGHT — everything, NULLs where it does not match." },
  { id: 'b_sqt_datetime', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'Dates do math', blurb: 'CURRENT_DATE / NOW() give today; subtract two dates for an interval; add time with INTERVAL. AGE(a, b) gives a human-readable gap.', code: "WHERE created > NOW() - INTERVAL '7 days';", lang: 'sql' },
  { id: 'b_sqt_dateextract', pack: 'sql-tutorial', topic: 'sql', level: 2, title: 'EXTRACT and DATE_TRUNC bucket time', blurb: "EXTRACT(YEAR FROM d) pulls one part; DATE_TRUNC('month', d) floors a timestamp to the start of its month — the key to time-series grouping.", code: "SELECT DATE_TRUNC('month', created) AS m, COUNT(*)\nFROM signups GROUP BY m;", lang: 'sql' },
  // ── advanced ──
  { id: 'b_sqt_cte', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'A CTE names a subquery', blurb: 'WITH t AS (...) defines a temporary, named result you SELECT from below — reads top-to-bottom like steps, far clearer than deep nesting.', code: 'WITH big AS (\n  SELECT * FROM sales WHERE amount > 1000\n)\nSELECT region, COUNT(*) FROM big GROUP BY region;', lang: 'sql', detail: "WHAT IT IS\nWITH name AS (...) defines a temporary, named result you can SELECT from below — like naming a step in a recipe.\nWHY BOTHER\nA query nested three subqueries deep is unreadable. A CTE flattens it into named steps you read top to bottom.\nCHAIN THEM\nA CTE can reference an earlier one, so you build a pipeline — filter, then aggregate, then rank — each its own clear block.\n```sql\nWITH big AS (\n  SELECT * FROM sales WHERE amount > 1000\n), by_region AS (\n  SELECT region, COUNT(*) n FROM big GROUP BY region\n)\nSELECT * FROM by_region ORDER BY n DESC;\n```\nVS A SUBQUERY\nReach for a CTE when the logic repeats or the query is deep. A plain subquery wins for a quick, single, inline use.\nREMEMBER\nA CTE is a name for a step. Names make queries readable." },
  { id: 'b_sqt_subquery', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'A subquery is a query inside a query', blurb: 'It can feed a value to WHERE (scalar), a list to IN, or a whole table to FROM. Inline and one-off — great when you use it once.', code: 'WHERE salary > (SELECT AVG(salary) FROM employees);', lang: 'sql', detail: "A QUERY AS A VALUE\nA subquery runs first and hands its result to the outer query — a single value (scalar), a list (for IN), or a whole table (in FROM).\nTHREE SHAPES\nScalar: WHERE salary > (SELECT AVG...). List: WHERE id IN (SELECT ...). Table: FROM (SELECT ...) AS t.\n```sql\nSELECT name FROM emp\nWHERE salary > (SELECT AVG(salary) FROM emp);\n```\nCORRELATED\nWhen the inner query references the outer row it re-runs per row — powerful but slow. A JOIN or window is often faster.\nREMEMBER\nSubquery = a query used as a value." },
  { id: 'b_sqt_cte_vs_sub', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'CTE vs subquery: clarity vs locality', blurb: 'Reach for a CTE when the logic repeats or the query is deep — it names each step. A subquery wins for a quick, single, inline use.' },
  { id: 'b_sqt_window_over', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Window functions compute without collapsing', blurb: 'OVER(...) runs an aggregate across a set of rows while keeping every row — so you get the total AND each row beside it.', code: 'SELECT name, salary,\n  AVG(salary) OVER () AS company_avg\nFROM employees;', lang: 'sql', detail: "THE SUPERPOWER\nA window function computes across a set of rows but KEEPS every row — so you see the aggregate AND the detail together. GROUP BY cannot.\nTHE ANATOMY\nfn() OVER (PARTITION BY ... ORDER BY ... frame). PARTITION is the groups, ORDER is the sequence, frame is which rows count.\n```sql\nSELECT name, salary,\n  AVG(salary) OVER () AS company_avg,\n  salary - AVG(salary) OVER () AS vs_avg\nFROM employees;\n```\nWHAT YOU GET\nRunning totals, ranks, moving averages, percent-of-total, period-over-period — all on the row, no self-join.\nREMEMBER\nOVER() = aggregate without collapsing." },
  { id: 'b_sqt_partitionby', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'PARTITION BY is GROUP BY for windows', blurb: 'It restarts the window per group, so the aggregate is computed within each partition but the rows stay intact.', code: 'AVG(salary) OVER (PARTITION BY dept)', lang: 'sql', detail: "WHY IT MATTERS\nPer-group stats without collapsing rows is the most-asked window pattern in interviews — and the base of running totals, ranks and shares.\nTHE MENTAL MODEL\nGROUP BY folds each group down to one row. PARTITION BY keeps every row and writes the group's answer beside it — the table keeps its shape, it just gains a column of context.\nEXAMPLE\n```sql\nSELECT name, dept, salary,\n  AVG(salary) OVER (PARTITION BY dept) AS dept_avg\nFROM employees;\n```\nRUNNING VALUES\nAdd ORDER BY inside OVER and the same aggregate becomes a running one — a cumulative sum, a moving average.\n```sql\nSUM(amount) OVER (PARTITION BY dept ORDER BY day)\n```\nPITFALLS\nWindow results can't be filtered in WHERE — it runs after. Wrap the query in a CTE and filter there.\nREMEMBER\nGROUP BY collapses. PARTITION BY annotates." },
  { id: 'b_sqt_runningsum', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'ORDER BY in a window = running total', blurb: 'Adding ORDER BY inside OVER accumulates row by row, giving a running sum (or any moving metric) up to each row.', code: 'SUM(amount) OVER (ORDER BY day) AS running_total', lang: 'sql', diagram: 'day  amt   running\n 1    5   →    5\n 2    3   →    8\n 3    4   →   12', detail: "ORDER MAKES IT RUN\nA plain SUM OVER (PARTITION BY x) is the whole-group total on every row. Add ORDER BY and it becomes CUMULATIVE — the sum up to each row.\n```sql\nSUM(amount) OVER (ORDER BY day) AS running_total\n-- day 1: 5 · day 2: 8 · day 3: 12\n```\nTHE FRAME\nORDER BY quietly sets the frame to start-through-current-row. Widen or narrow it with ROWS BETWEEN for a moving window — a 7-day trailing sum, say.\nREMEMBER\nNo ORDER BY, whole group. ORDER BY, running." },
  { id: 'b_sqt_firstlast', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'LAST_VALUE needs a full frame', blurb: 'With ORDER BY, the default frame ends at the current row — so LAST_VALUE looks like FIRST_VALUE until you widen it to UNBOUNDED FOLLOWING.', code: 'LAST_VALUE(price) OVER (\n  ORDER BY day\n  ROWS BETWEEN UNBOUNDED PRECEDING\n           AND UNBOUNDED FOLLOWING)', lang: 'sql' },
  { id: 'b_sqt_ranks', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'ROW_NUMBER vs RANK vs DENSE_RANK', blurb: 'ROW_NUMBER: always 1,2,3 (no ties). RANK: ties share a number, then it skips (1,1,3). DENSE_RANK: ties share, no gap (1,1,2).', code: 'RANK() OVER (ORDER BY score DESC)', lang: 'sql', detail: "THE THREE\nAll three number the rows of an ordered window. They differ only in how they treat TIES.\nROW_NUMBER\nAlways 1, 2, 3, 4 — every row a distinct number, even on ties (broken arbitrarily unless you add a tiebreaker to ORDER BY).\nRANK\nTies share a number, then it SKIPS: 1, 1, 3, 4. The gap tells you how many were tied.\nDENSE_RANK\nTies share, no gap: 1, 1, 2, 3. Use it for 'the top 3 distinct scores'.\nEXAMPLE\n```sql\nSELECT name, score,\n  RANK()       OVER (ORDER BY score DESC) AS rnk,\n  DENSE_RANK() OVER (ORDER BY score DESC) AS dense\nFROM players;\n```\nREMEMBER\nROW_NUMBER never ties. RANK skips. DENSE_RANK doesn't." },
  { id: 'b_sqt_topn', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Top-N per group with a ranked CTE', blurb: "Number rows within each partition, then filter in an outer query — the standard 'top 3 per category' pattern.", code: 'WITH r AS (\n  SELECT *, ROW_NUMBER() OVER (\n    PARTITION BY dept ORDER BY salary DESC) rn\n  FROM emp)\nSELECT * FROM r WHERE rn <= 3;', lang: 'sql', detail: "THE PATTERN\nTop 3 per category means: number the rows within each group, then keep the low numbers. ROW_NUMBER in a CTE, filter outside.\n```sql\nWITH r AS (\n  SELECT *, ROW_NUMBER() OVER (\n    PARTITION BY dept ORDER BY salary DESC) rn\n  FROM emp)\nSELECT * FROM r WHERE rn <= 3;\n```\nWHY THE CTE\nYou cannot filter a window function in WHERE (it runs after WHERE). Compute rn in a CTE, then filter it outside.\nROW_NUMBER OR RANK\nROW_NUMBER gives exactly 3 even on ties; RANK includes ties, so you might get more. Pick by whether ties should share the podium.\nREMEMBER\nNumber in a CTE, filter outside." },
  { id: 'b_sqt_leadlag', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'LAG looks back, LEAD looks ahead', blurb: 'They pull a value from a previous or next row in the ordered window — the basis of period-over-period change.', code: 'LAG(revenue) OVER (ORDER BY month) AS prev_month', lang: 'sql', detail: "NEIGHBOURS IN THE WINDOW\nLAG(x) grabs x from the PREVIOUS row, LEAD(x) from the NEXT — in the window's ORDER BY sequence. The basis of change-over-time.\nPERIOD OVER PERIOD\nSubtract the lag for month-over-month growth — no self-join.\n```sql\nSELECT month, revenue,\n  revenue - LAG(revenue) OVER (ORDER BY month)\n    AS mom_change\nFROM monthly;\n```\nDEFAULTS + OFFSET\nThe first row's LAG is NULL — pass a default: LAG(x, 1, 0). And LAG(x, 2) looks back two rows.\nREMEMBER\nLAG is the previous row, LEAD the next." },
  { id: 'b_sqt_leadlag_use', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Month-over-month with LAG', blurb: 'Subtract the lagged value from the current row to get the delta or growth rate — no self-join required.', code: 'revenue - LAG(revenue) OVER (ORDER BY month)\n  AS mom_change', lang: 'sql' },
  { id: 'b_sqt_selfjoin', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'A self-join joins a table to itself', blurb: 'Alias the table twice to relate rows within it — employees to their managers, or pairs in a group. Add a.id < b.id to drop mirror duplicates.', code: 'FROM employees e\nJOIN employees m ON e.manager_id = m.id;', lang: 'sql', diagram: 'employees e ──e.manager_id──▶ employees m\n   (one table, two aliases)', detail: "ONE TABLE, TWO ROLES\nAlias the same table twice and join it to itself — to relate rows WITHIN a table: employee to manager, event to prior event, pairs in a group.\n```sql\nSELECT e.name AS emp, m.name AS mgr\nFROM employees e\nJOIN employees m ON e.manager_id = m.id;\n```\nPAIRS WITHOUT DUPLICATES\nListing pairs in a group? Add a.id < b.id so you get (A,B) but not also (B,A), and never (A,A).\nREMEMBER\nSelf-join: a table related to itself, through aliases." },
  { id: 'b_sqt_union', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'UNION dedupes, UNION ALL keeps all', blurb: 'Both stack two result sets vertically. UNION removes duplicate rows (and pays to sort); UNION ALL keeps every row and is faster.', code: 'SELECT id FROM a\nUNION ALL\nSELECT id FROM b;', lang: 'sql', diagram: 'A = {1, 2}   B = {2, 3}\n\nUNION      →  1 2 3      (deduped)\nUNION ALL  →  1 2 2 3    (everything)', detail: "STACKING RESULTS\nUNION and UNION ALL stack two result sets vertically — same columns, same order, compatible types. The vertical counterpart to a JOIN.\nTHE ONE DIFFERENCE\nUNION removes duplicate rows (and pays a sort to find them). UNION ALL keeps everything and is faster. Default to UNION ALL unless you truly need the dedup.\n```sql\nSELECT id FROM active\nUNION ALL\nSELECT id FROM archived;\n```\nCOUSINS\nINTERSECT is rows in both. EXCEPT is in the first, not the second. Same column rules.\nREMEMBER\nUNION dedupes; UNION ALL does not, and is faster." },
  { id: 'b_sqt_intersect', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'INTERSECT: rows in both', blurb: "It returns only rows appearing in both queries — the overlap. Think 'users who bought A and B'.", code: 'SELECT user_id FROM bought_a\nINTERSECT\nSELECT user_id FROM bought_b;', lang: 'sql' },
  { id: 'b_sqt_except', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'EXCEPT: in the first, not the second', blurb: "Rows from the first query that aren't in the second — the difference. 'Signed up but never purchased.'", code: 'SELECT user_id FROM signups\nEXCEPT\nSELECT user_id FROM purchases;', lang: 'sql' },
  { id: 'b_sqt_setop_rules', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Set operations need matching columns', blurb: 'UNION, INTERSECT and EXCEPT require both queries to have the same number of columns, in the same order, with compatible types.' },
  { id: 'b_sqt_orderexec', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'SQL runs FROM before SELECT', blurb: "Logical order: FROM/JOIN, WHERE, GROUP BY, HAVING, SELECT, ORDER BY, LIMIT. That's why a SELECT alias can't be used in WHERE but can in ORDER BY.", detail: "WRITTEN VS RUN\nYou write SELECT first, but SQL runs it nearly last. The real order: FROM/JOIN, WHERE, GROUP BY, HAVING, SELECT, ORDER BY, LIMIT.\nWHY IT MATTERS\nA column alias made in SELECT does not exist yet in WHERE or GROUP BY (they ran first) — but it DOES in ORDER BY, which runs after SELECT.\n```sql\nSELECT price * qty AS total\nFROM sales\nWHERE total > 100      -- alias not defined yet\nORDER BY total;        -- but fine here\n```\nREMEMBER\nFROM first, SELECT late, ORDER BY last." },
  { id: 'b_sqt_bestpractice', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Clean SQL reads like a paragraph', blurb: 'Uppercase keywords, snake_case names, meaningful aliases, one clause per line, explicit JOIN types, no SELECT * in production. Future-you is the reader.' },
  { id: 'b_sqt_pivot', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Pivot rows into columns with CASE', blurb: 'Wrap a CASE inside an aggregate, one per target column, and GROUP BY the row key — turns long data wide.', code: "SELECT user_id,\n  SUM(CASE WHEN platform='ios' THEN mins END) AS ios,\n  SUM(CASE WHEN platform='web' THEN mins END) AS web\nFROM usage GROUP BY user_id;", lang: 'sql', detail: "LONG TO WIDE\nA pivot turns row categories into columns. The trick: one aggregated CASE per target column, grouped by the row key.\n```sql\nSELECT user_id,\n  SUM(CASE WHEN platform='ios' THEN mins END) AS ios,\n  SUM(CASE WHEN platform='web' THEN mins END) AS web\nFROM usage GROUP BY user_id;\n```\nWHY THE AGGREGATE\nEach cell is many rows collapsed to one number, so it must sit inside SUM/COUNT/MAX. The CASE picks which rows feed which column.\nUNPIVOT\nWide back to long is the reverse: one SELECT per column, stacked with UNION ALL.\nREMEMBER\nPivot = aggregate(CASE per column) + GROUP BY." },
  { id: 'b_sqt_unpivot', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Unpivot columns into rows with UNION ALL', blurb: 'Stack one SELECT per column, each labelling its source — turns wide data long, the shape most aggregates want.', code: "SELECT user_id, 'ios' AS platform, ios AS mins FROM t\nUNION ALL\nSELECT user_id, 'web', web FROM t;", lang: 'sql' },
  { id: 'b_sqt_str_case', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'UPPER / LOWER normalise text', blurb: "Fold case before comparing or grouping so 'Gmail' and 'gmail' match. Often paired with TRIM to tidy messy input.", code: 'WHERE LOWER(email) = LOWER(:input);', lang: 'sql' },
  { id: 'b_sqt_str_sub', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Slice strings: LEFT, RIGHT, SUBSTRING', blurb: 'LEFT(s, n) / RIGHT(s, n) take from the ends; SUBSTRING(s FROM p FOR n) takes a middle slice; LENGTH(s) measures.', code: 'SELECT LEFT(phone, 3) AS area_code\nFROM contacts;', lang: 'sql' },
  { id: 'b_sqt_str_trim', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'TRIM strips surrounding spaces', blurb: 'TRIM removes leading and trailing spaces (LTRIM/RTRIM do one side, BTRIM both). Essential for data typed by humans.', code: 'SELECT TRIM(name) FROM imports;', lang: 'sql' },
  { id: 'b_sqt_str_concat', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'CONCAT joins, CONCAT_WS adds a separator', blurb: 'CONCAT(a, b) glues values; CONCAT_WS(sep, a, b, c) inserts the separator between them and skips NULLs.', code: "SELECT CONCAT_WS(' ', first, last) AS full_name\nFROM users;", lang: 'sql' },
  { id: 'b_sqt_str_split', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'SPLIT_PART and POSITION dissect text', blurb: 'SPLIT_PART(s, delim, n) grabs the n-th chunk; POSITION(sub IN s) finds where a substring starts (0 if absent).', code: "SELECT SPLIT_PART(email, '@', 2) AS domain\nFROM users;", lang: 'sql' },
  { id: 'b_sqt_casestudy', pack: 'sql-tutorial', topic: 'sql', level: 3, title: 'Analytics is question -> query -> story', blurb: 'A real case study starts from a business question, breaks it into aggregates and window functions, then reads the numbers back as a recommendation. SQL is the middle step, not the point.' },
];

